{
  "name": "Trúc Xanh - Memory Match",
  "description": "A beautiful and interactive Vietnamese-style Memory Match game (Trúc Xanh) where players find pairs of matching emojis generated by Gemini AI."
}

export interface CardData {
  id: number;
  content: string;
  isFlipped: boolean;
  isMatched: boolean;
}

export enum GameStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  PLAYING = 'PLAYING',
  WON = 'WON'
}

export interface GameTheme {
  name: string;
  emojis: string[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { GameTheme } from "../types";

export const getThemeFromGemini = async (userPrompt: string): Promise<GameTheme> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate 6 unique emojis for a memory match game based on this theme: "${userPrompt}". If the theme is vague, pick something fun like animals or food. Return the theme name and the 6 emojis.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING, description: "A catchy name for the theme" },
          emojis: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "List of exactly 6 unique emojis"
          }
        },
        required: ["name", "emojis"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text || '{}');
    // Ensure we have exactly 6 emojis
    if (data.emojis && data.emojis.length >= 6) {
      return {
        name: data.name,
        emojis: data.emojis.slice(0, 6)
      };
    }
    throw new Error("Invalid emoji count");
  } catch (error) {
    console.error("Error parsing Gemini response", error);
    // Fallback theme
    return {
      name: "Trái Cây Nhiệt Đới",
      emojis: ["🍎", "🍌", "🍇", "🍓", "🍍", "🍉"]
    };
  }
};

