import React, { useState, useEffect, useCallback } from 'react';
import { CardData, GameStatus, GameTheme } from './types';
import { getThemeFromGemini } from './services/geminiService';
import { Card } from './components/Card';

const DEFAULT_THEME: GameTheme = {
  name: "Động vật",
  emojis: ["🐶", "🐱", "🐭", "🐹", "🐰", "🦊"]
};

const App: React.FC = () => {
  const [theme, setTheme] = useState<GameTheme>(DEFAULT_THEME);
  const [cards, setCards] = useState<CardData[]>([]);
  const [flippedIndices, setFlippedIndices] = useState<number[]>([]);
  const [status, setStatus] = useState<GameStatus>(GameStatus.IDLE);
  const [moves, setMoves] = useState(0);
  const [bestScore, setBestScore] = useState<number | null>(null);
  const [prompt, setPrompt] = useState("");

  const initializeGame = useCallback((gameTheme: GameTheme) => {
    const pairEmojis = [...gameTheme.emojis, ...gameTheme.emojis];
    const shuffledCards: CardData[] = pairEmojis
      .sort(() => Math.random() - 0.5)
      .map((emoji, index) => ({
        id: index,
        content: emoji,
        isFlipped: false,
        isMatched: false
      }));

    setCards(shuffledCards);
    setFlippedIndices([]);
    setMoves(0);
    setStatus(GameStatus.PLAYING);
    setTheme(gameTheme);
  }, []);

  useEffect(() => {
    // Initial load
    initializeGame(DEFAULT_THEME);
  }, [initializeGame]);

  const handleCardClick = (id: number) => {
    if (flippedIndices.length === 2 || status !== GameStatus.PLAYING) return;

    const newFlipped = [...flippedIndices, id];
    setFlippedIndices(newFlipped);

    // If we have two cards flipped, check for match
    if (newFlipped.length === 2) {
      setMoves(prev => prev + 1);
      const [firstId, secondId] = newFlipped;

      if (cards[firstId].content === cards[secondId].content) {
        // Match found
        setTimeout(() => {
          setCards(prev => prev.map(card => 
            (card.id === firstId || card.id === secondId) 
              ? { ...card, isMatched: true } 
              : card
          ));
          setFlippedIndices([]);
        }, 600);
      } else {
        // No match
        setTimeout(() => {
          setFlippedIndices([]);
        }, 1200);
      }
    }
  };

  // Check victory
  useEffect(() => {
    if (cards.length > 0 && cards.every(card => card.isMatched)) {
      setStatus(GameStatus.WON);
      if (bestScore === null || moves < bestScore) {
        setBestScore(moves);
      }
    }
  }, [cards, moves, bestScore]);

  const handleNewTheme = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;

    setStatus(GameStatus.LOADING);
    const newTheme = await getThemeFromGemini(prompt);
    initializeGame(newTheme);
    setPrompt("");
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 md:py-12 min-h-screen flex flex-col">
      <header className="text-center mb-8">
        <h1 className="text-4xl md:text-5xl font-extrabold text-emerald-800 mb-2 flex items-center justify-center gap-3">
          <i className="fa-solid fa-leaf text-emerald-500"></i>
          TRÚC XANH
        </h1>
        <p className="text-slate-600 font-medium">Memory Matching Challenge</p>
      </header>

      <main className="flex-grow flex flex-col lg:flex-row gap-8 items-start">
        {/* Controls Panel */}
        <div className="w-full lg:w-1/3 space-y-6 order-2 lg:order-1">
          <div className="bg-white rounded-2xl p-6 shadow-xl border border-emerald-100">
            <h2 className="text-xl font-bold text-emerald-900 mb-4 flex items-center gap-2">
              <i className="fa-solid fa-gamepad"></i>
              Thông số
            </h2>
            <div className="grid grid-cols-2 gap-4 mb-6">
              <div className="bg-emerald-50 p-4 rounded-xl text-center">
                <p className="text-xs text-emerald-600 uppercase font-bold mb-1">Số lượt</p>
                <p className="text-2xl font-black text-emerald-900">{moves}</p>
              </div>
              <div className="bg-emerald-50 p-4 rounded-xl text-center">
                <p className="text-xs text-emerald-600 uppercase font-bold mb-1">Kỷ lục</p>
                <p className="text-2xl font-black text-emerald-900">{bestScore ?? '--'}</p>
              </div>
            </div>

            <form onSubmit={handleNewTheme} className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Đổi chủ đề (AI gợi ý)</label>
                <div className="relative">
                  <input 
                    type="text" 
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    placeholder="VD: Không gian, Đồ ăn..."
                    className="w-full pl-4 pr-10 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-emerald-500 transition-all text-sm"
                    disabled={status === GameStatus.LOADING}
                  />
                  <button 
                    type="submit"
                    className="absolute right-2 top-2 p-1.5 text-emerald-600 hover:text-emerald-700 disabled:opacity-50"
                    disabled={status === GameStatus.LOADING}
                  >
                    <i className={`fa-solid ${status === GameStatus.LOADING ? 'fa-spinner fa-spin' : 'fa-wand-magic-sparkles'}`}></i>
                  </button>
                </div>
              </div>

              <button 
                onClick={() => initializeGame(theme)}
                className="w-full py-3 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2"
              >
                <i className="fa-solid fa-rotate-right"></i>
                Chơi lại
              </button>
            </form>
          </div>

          <div className="bg-emerald-900 text-emerald-100 p-6 rounded-2xl shadow-xl">
             <h3 className="font-bold mb-2 flex items-center gap-2">
               <i className="fa-solid fa-circle-info text-emerald-400"></i>
               Cách chơi
             </h3>
             <ul className="text-sm space-y-2 opacity-80">
               <li>• Lật 2 ô bất kỳ để tìm cặp giống nhau.</li>
               <li>• Nếu giống nhau, chúng sẽ ở lại.</li>
               <li>• Tìm hết tất cả các cặp để thắng!</li>
               <li>• Thử thách AI tạo chủ đề mới bất kỳ lúc nào.</li>
             </ul>
          </div>
        </div>

        {/* Game Board */}
        <div className="flex-grow w-full order-1 lg:order-2">
          {status === GameStatus.LOADING ? (
             <div className="w-full aspect-square md:aspect-auto md:h-[500px] flex flex-col items-center justify-center bg-white rounded-3xl border-2 border-dashed border-emerald-200 shadow-inner">
                <div className="relative mb-6">
                  <div className="w-20 h-20 border-4 border-emerald-200 border-t-emerald-600 rounded-full animate-spin"></div>
                  <i className="fa-solid fa-leaf text-2xl text-emerald-600 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2"></i>
                </div>
                <p className="text-emerald-800 font-bold animate-pulse text-lg">AI đang chuẩn bị thẻ bài...</p>
                <p className="text-slate-400 text-sm mt-2 italic">"{theme.name}"</p>
             </div>
          ) : (
            <div className="relative">
              <div className="grid grid-cols-3 md:grid-cols-4 gap-3 md:gap-4 p-4 md:p-6 bg-emerald-100/50 rounded-3xl border-4 border-emerald-100 shadow-inner">
                {cards.map((card, index) => (
                  <Card 
                    key={card.id} 
                    card={{
                      ...card,
                      isFlipped: flippedIndices.includes(card.id)
                    }} 
                    onClick={handleCardClick}
                    disabled={status === GameStatus.WON || status === GameStatus.LOADING}
                  />
                ))}
              </div>

              {status === GameStatus.WON && (
                <div className="absolute inset-0 bg-emerald-900/40 backdrop-blur-sm rounded-3xl flex items-center justify-center z-20 transition-all">
                  <div className="bg-white p-8 rounded-2xl shadow-2xl text-center transform animate-[bounce_1s_ease-in-out_infinite] scale-110 border-t-8 border-yellow-400">
                    <div className="text-6xl mb-4">🏆</div>
                    <h2 className="text-3xl font-black text-emerald-900 mb-2">CHIẾN THẮNG!</h2>
                    <p className="text-slate-600 mb-6 font-medium">Bạn đã hoàn thành với <span className="text-emerald-600 font-bold">{moves}</span> lượt đi.</p>
                    <button 
                      onClick={() => initializeGame(theme)}
                      className="px-8 py-3 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-full shadow-lg transition-all active:scale-95"
                    >
                      Chơi Lại
                    </button>
                  </div>
                </div>
              )}
            </div>
          )}

          <div className="mt-6 flex items-center justify-between px-2">
            <span className="text-emerald-800 font-bold flex items-center gap-2">
              <i className="fa-solid fa-palette"></i>
              Chủ đề: <span className="text-emerald-600">{theme.name}</span>
            </span>
            <span className="text-slate-400 text-xs italic">Sáng tạo bởi Gemini Flash</span>
          </div>
        </div>
      </main>

      <footer className="mt-12 text-center text-slate-400 text-sm border-t border-emerald-100 pt-6">
        <p>© 2024 Trúc Xanh AI. Ghép đôi niềm vui với trí tuệ nhân tạo.</p>
      </footer>
    </div>
  );
};

export default App;

