class AudioService {
  private ctx: AudioContext | null = null;

  private init() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  }

  private playTone(freq: number, type: OscillatorType, duration: number, volume: number = 0.1) {
    this.init();
    if (!this.ctx) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, this.ctx.currentTime);

    gain.gain.setValueAtTime(volume, this.ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.0001, this.ctx.currentTime + duration);

    osc.connect(gain);
    gain.connect(this.ctx.destination);

    osc.start();
    osc.stop(this.ctx.currentTime + duration);
  }

  playFlip() {
    this.playTone(400, 'sine', 0.1, 0.05);
  }

  playMatch() {
    this.playTone(523.25, 'sine', 0.5, 0.1); // C5
    setTimeout(() => this.playTone(659.25, 'sine', 0.5, 0.1), 100); // E5
    setTimeout(() => this.playTone(783.99, 'sine', 0.5, 0.1), 200); // G5
  }

  playWrong() {
    this.playTone(200, 'sawtooth', 0.3, 0.05);
    setTimeout(() => this.playTone(150, 'sawtooth', 0.3, 0.05), 150);
  }

  playVictory() {
    const tones = [523, 659, 783, 1046];
    tones.forEach((t, i) => {
      setTimeout(() => this.playTone(t, 'square', 0.6, 0.05), i * 150);
    });
  }
}

export const audioService = new AudioService();

import { GoogleGenAI, Type } from "@google/genai";
import { GameTheme } from "../types";

export const getThemeFromGemini = async (userPrompt: string): Promise<GameTheme> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate 6 unique items for a Vietnamese memory match game "Trúc Xanh" based on: "${userPrompt}". 
    For each item, provide an emoji and a simple trivia question related to it with 4 options and 1 correct answer.
    Return the theme name and the items list.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          items: { 
            type: Type.ARRAY, 
            items: { 
              type: Type.OBJECT,
              properties: {
                emoji: { type: Type.STRING },
                quiz: {
                  type: Type.OBJECT,
                  properties: {
                    question: { type: Type.STRING },
                    options: { type: Type.ARRAY, items: { type: Type.STRING } },
                    correctAnswer: { type: Type.STRING }
                  },
                  required: ["question", "options", "correctAnswer"]
                }
              },
              required: ["emoji", "quiz"]
            }
          }
        },
        required: ["name", "items"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text || '{}');
    if (data.items && data.items.length >= 6) {
      return {
        name: data.name,
        items: data.items.slice(0, 6)
      };
    }
    throw new Error("Invalid data");
  } catch (error) {
    console.error("Gemini Error", error);
    return {
      name: "Trái Cây",
      items: [
        { emoji: "🍎", quiz: { question: "Táo có màu gì phổ biến nhất?", options: ["Xanh", "Đỏ", "Tím", "Vàng"], correctAnswer: "Đỏ" } },
        { emoji: "🍌", quiz: { question: "Chuối cung cấp nhiều chất gì?", options: ["Sắt", "Kali", "Canxi", "Kẽm"], correctAnswer: "Kali" } },
        { emoji: "🍇", quiz: { question: "Nho khô được làm từ gì?", options: ["Táo", "Nho tươi", "Mận", "Đào"], correctAnswer: "Nho tươi" } },
        { emoji: "🍓", quiz: { question: "Dâu tây thường trồng ở đâu tại VN?", options: ["Cần Thơ", "Đà Lạt", "Hà Nội", "Huế"], correctAnswer: "Đà Lạt" } },
        { emoji: "🍍", quiz: { question: "Quả dứa còn gọi là quả gì?", options: ["Mận", "Thơm", "Ổi", "Xoài"], correctAnswer: "Thơm" } },
        { emoji: "🍉", quiz: { question: "Dưa hấu có ruột màu gì?", options: ["Xanh", "Đỏ", "Trắng", "Đen"], correctAnswer: "Đỏ" } }
      ]
    };
  }
};

