import { QuestionModal } from './components/QuestionModal';

const INITIAL_TIME = 120; // 2 minutes

const App: React.FC = () => {
  const [theme, setTheme] = useState<GameTheme | null>(null);
  const [cards, setCards] = useState<CardData[]>([]);
  const [flippedIndices, setFlippedIndices] = useState<number[]>([]);
  const [status, setStatus] = useState<GameStatus>(GameStatus.IDLE);
  const [activeTeam, setActiveTeam] = useState(0); // 0 = Team 1, 1 = Team 2
  const [scores, setScores] = useState([0, 0]);
  const [timeLeft, setTimeLeft] = useState(INITIAL_TIME);
  const [activeQuestion, setActiveQuestion] = useState<QuizQuestion | null>(null);
  const [prompt, setPrompt] = useState("");

  const timerRef = useRef<number | null>(null);

  const startTimer = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timerRef.current!);
          setStatus(GameStatus.TIME_UP);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  };

  const initializeGame = useCallback(async (gameTheme: GameTheme) => {
    const cardPairs: CardData[] = [];
    gameTheme.items.forEach((item, idx) => {
      // Two identical cards for each emoji
      const cardBase = { content: item.emoji, isFlipped: false, isMatched: false, question: item.quiz };
      cardPairs.push({ ...cardBase, id: idx * 2 });
      cardPairs.push({ ...cardBase, id: idx * 2 + 1 });
    });

    const shuffled = cardPairs.sort(() => Math.random() - 0.5);
    setCards(shuffled);
    setTheme(gameTheme);
    setScores([0, 0]);
    setActiveTeam(0);
    setTimeLeft(INITIAL_TIME);
    setStatus(GameStatus.PLAYING);
    setFlippedIndices([]);
    startTimer();
  }, []);

  useEffect(() => {
    const loadDefault = async () => {
      setStatus(GameStatus.LOADING);
      const defaultTheme = await getThemeFromGemini("Trái cây và Động vật");
      initializeGame(defaultTheme);
    };
    loadDefault();
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [initializeGame]);

  const handleCardClick = (id: number) => {
    if (flippedIndices.length === 2 || status !== GameStatus.PLAYING) return;

    audioService.playFlip();
    const newFlipped = [...flippedIndices, id];
    setFlippedIndices(newFlipped);

    if (newFlipped.length === 2) {
      const card1 = cards.find(c => c.id === newFlipped[0]);
      const card2 = cards.find(c => c.id === newFlipped[1]);

      if (card1?.content === card2?.content) {
        // MATCH!
        setTimeout(() => {
          audioService.playMatch();
          setActiveQuestion(card1!.question || null);
          setStatus(GameStatus.QUESTION);
          // Mark cards as matched immediately but wait for quiz for points/turn
          setCards(prev => prev.map(c => 
            (c.id === card1!.id || c.id === card2!.id) ? { ...c, isMatched: true } : c
          ));
        }, 600);
      } else {
        // NO MATCH
        setTimeout(() => {
          audioService.playWrong();
          setFlippedIndices([]);
          setActiveTeam(prev => (prev === 0 ? 1 : 0));
        }, 1200);
      }
    }
  };

  const handleAnswer = (correct: boolean) => {
    if (correct) {
      audioService.playMatch();
      setScores(prev => {
        const next = [...prev];
        next[activeTeam] += 10;
        return next;
      });
      // Keep turn
    } else {
      audioService.playWrong();
      // Lose turn
      setActiveTeam(prev => (prev === 0 ? 1 : 0));
    }

    setActiveQuestion(null);
    setStatus(GameStatus.PLAYING);
    setFlippedIndices([]);

    // Check Win
    if (cards.every(c => c.isMatched)) {
      setStatus(GameStatus.WON);
      audioService.playVictory();
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const handleNewTheme = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() || status === GameStatus.LOADING) return;
    setStatus(GameStatus.LOADING);
    const newTheme = await getThemeFromGemini(prompt);
    initializeGame(newTheme);
    setPrompt("");
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-6 md:py-10 min-h-screen flex flex-col font-sans">
      {/* Header & Stats */}
      <header className="flex flex-col md:flex-row items-center justify-between mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-3 rounded-2xl shadow-lg">
            <i className="fa-solid fa-leaf text-white text-3xl"></i>
          </div>
          <div>
            <h1 className="text-3xl font-black text-emerald-900 leading-tight">TRÚC XANH</h1>
            <p className="text-emerald-600 text-xs font-bold tracking-widest uppercase">Vietnamese Memory Quiz</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3 bg-white px-6 py-3 rounded-2xl shadow-md border border-slate-100">
             <i className="fa-solid fa-clock text-emerald-500 animate-pulse"></i>
             <span className={`text-2xl font-mono font-bold ${timeLeft < 20 ? 'text-red-500 animate-bounce' : 'text-slate-700'}`}>
               {formatTime(timeLeft)}
             </span>
          </div>
        </div>
      </header>

      {/* Main Game Area */}
      <main className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start flex-grow">

        {/* Scoreboard Left */}
        <div className="lg:col-span-3 space-y-4">
          <div className={`p-6 rounded-3xl transition-all duration-500 border-4 ${
            activeTeam === 0 
            ? 'bg-blue-600 border-blue-400 shadow-[0_0_20px_rgba(59,130,246,0.5)] scale-105' 
            : 'bg-white border-slate-100 opacity-60'
          }`}>
            <div className="flex items-center gap-3 mb-4">
               <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center">
                 <i className={`fa-solid fa-user ${activeTeam === 0 ? 'text-white' : 'text-blue-500'}`}></i>
               </div>
               <h3 className={`font-black text-lg ${activeTeam === 0 ? 'text-white' : 'text-slate-800'}`}>ĐỘI 1</h3>
            </div>
            <p className={`text-4xl font-black ${activeTeam === 0 ? 'text-white' : 'text-blue-600'}`}>{scores[0]}</p>
            {activeTeam === 0 && <span className="text-blue-100 text-[10px] font-bold uppercase mt-2 block tracking-widest">Đang lật bài...</span>}
          </div>

          <div className={`p-6 rounded-3xl transition-all duration-500 border-4 ${
            activeTeam === 1 
            ? 'bg-red-600 border-red-400 shadow-[0_0_20px_rgba(239,68,68,0.5)] scale-105' 
            : 'bg-white border-slate-100 opacity-60'
          }`}>
            <div className="flex items-center gap-3 mb-4">
               <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center">
                 <i className={`fa-solid fa-user ${activeTeam === 1 ? 'text-white' : 'text-red-500'}`}></i>
               </div>
               <h3 className={`font-black text-lg ${activeTeam === 1 ? 'text-white' : 'text-slate-800'}`}>ĐỘI 2</h3>
            </div>
            <p className={`text-4xl font-black ${activeTeam === 1 ? 'text-white' : 'text-red-600'}`}>{scores[1]}</p>
            {activeTeam === 1 && <span className="text-red-100 text-[10px] font-bold uppercase mt-2 block tracking-widest">Đang lật bài...</span>}
          </div>

          <form onSubmit={handleNewTheme} className="bg-white p-6 rounded-3xl shadow-xl border border-emerald-50">
             <label className="text-sm font-bold text-slate-700 block mb-2">Chủ đề mới</label>
             <div className="flex gap-2">
                <input 
                  type="text" 
                  value={prompt}
                  onChange={e => setPrompt(e.target.value)}
                  placeholder="VD: Không gian..."
                  className="flex-grow bg-slate-50 border-none rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
                />
                <button type="submit" className="bg-emerald-600 text-white p-2 rounded-xl hover:bg-emerald-700 transition-colors">
                  <i className="fa-solid fa-wand-magic-sparkles"></i>
                </button>
             </div>
          </form>
        </div>

        {/* Board Middle */}
        <div className="lg:col-span-9">
          {status === GameStatus.LOADING ? (
            <div className="bg-white rounded-[2rem] aspect-square flex flex-col items-center justify-center border-4 border-emerald-100 shadow-inner">
               <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
               <p className="text-emerald-800 font-bold">AI đang sắp xếp thẻ bài...</p>
            </div>
          ) : (
            <div className="grid grid-cols-3 md:grid-cols-4 gap-4 p-4 md:p-8 bg-emerald-100/30 rounded-[2.5rem] border-2 border-emerald-100/50 shadow-inner">
              {cards.map((card, idx) => (
                <Card 
                  key={card.id} 
                  card={{...card, isFlipped: flippedIndices.includes(card.id)}} 
                  index={idx}
                  onClick={handleCardClick}
                  disabled={status !== GameStatus.PLAYING}
                />
              ))}
            </div>
          )}
        </div>
      </main>

      {/* Overlays */}
      {activeQuestion && <QuestionModal question={activeQuestion} onAnswer={handleAnswer} />}

      {(status === GameStatus.WON || status === GameStatus.TIME_UP) && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-lg z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] p-10 max-w-lg w-full text-center shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-500 via-emerald-500 to-red-500"></div>
            <div className="text-7xl mb-6">🏁</div>
            <h2 className="text-4xl font-black text-slate-900 mb-2">
              {status === GameStatus.TIME_UP ? "HẾT GIỜ!" : "HOÀN THÀNH!"}
            </h2>

            <div className="grid grid-cols-2 gap-4 my-8">
               <div className={`p-4 rounded-2xl ${scores[0] >= scores[1] ? 'bg-blue-50 border-2 border-blue-500' : 'bg-slate-50'}`}>
                 <p className="text-xs font-bold text-slate-500 uppercase">Đội 1</p>
                 <p className="text-3xl font-black text-blue-600">{scores[0]}</p>
                 {scores[0] >= scores[1] && <span className="text-[10px] font-black text-blue-500">THẮNG!</span>}
               </div>
               <div className={`p-4 rounded-2xl ${scores[1] >= scores[0] ? 'bg-red-50 border-2 border-red-500' : 'bg-slate-50'}`}>
                 <p className="text-xs font-bold text-slate-500 uppercase">Đội 2</p>
                 <p className="text-3xl font-black text-red-600">{scores[1]}</p>
                 {scores[1] >= scores[0] && <span className="text-[10px] font-black text-red-500">THẮNG!</span>}
               </div>
            </div>

            <button 
              onClick={() => theme && initializeGame(theme)}
              className="w-full py-5 bg-emerald-600 hover:bg-emerald-700 text-white font-black rounded-2xl shadow-xl transition-all active:scale-95 text-xl"
            >
              CHƠI VÁN MỚI
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { CardData, GameStatus, GameTheme, QuizQuestion } from './types';
import { getThemeFromGemini } from './services/geminiService';
import { audioService } from './services/audioService';
import { Card } from './components/Card';
import { QuestionModal } from './components/QuestionModal';

const INITIAL_TIME = 120; // 2 minutes
const TOTAL_TEAMS = 5;

const TEAM_COLORS = [
  { bg: 'bg-blue-600', border: 'border-blue-400', shadow: 'shadow-[0_0_20px_rgba(59,130,246,0.5)]', text: 'text-blue-600', light: 'bg-blue-50' },
  { bg: 'bg-red-600', border: 'border-red-400', shadow: 'shadow-[0_0_20px_rgba(239,68,68,0.5)]', text: 'text-red-600', light: 'bg-red-50' },
  { bg: 'bg-amber-500', border: 'border-amber-400', shadow: 'shadow-[0_0_20px_rgba(245,158,11,0.5)]', text: 'text-amber-500', light: 'bg-amber-50' },
  { bg: 'bg-purple-600', border: 'border-purple-400', shadow: 'shadow-[0_0_20px_rgba(147,51,234,0.5)]', text: 'text-purple-600', light: 'bg-purple-50' },
  { bg: 'bg-teal-600', border: 'border-teal-400', shadow: 'shadow-[0_0_20px_rgba(13,148,136,0.5)]', text: 'text-teal-600', light: 'bg-teal-50' },
];

const App: React.FC = () => {
  const [theme, setTheme] = useState<GameTheme | null>(null);
  const [cards, setCards] = useState<CardData[]>([]);
  const [flippedIndices, setFlippedIndices] = useState<number[]>([]);
  const [status, setStatus] = useState<GameStatus>(GameStatus.IDLE);
  const [activeTeam, setActiveTeam] = useState(0); // 0 to 4
  const [scores, setScores] = useState([0, 0, 0, 0, 0]);
  const [timeLeft, setTimeLeft] = useState(INITIAL_TIME);
  const [activeQuestion, setActiveQuestion] = useState<QuizQuestion | null>(null);
  const [prompt, setPrompt] = useState("");

  const timerRef = useRef<number | null>(null);

  const startTimer = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    timerRef.current = window.setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timerRef.current!);
          setStatus(GameStatus.TIME_UP);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
  };

  const initializeGame = useCallback(async (gameTheme: GameTheme) => {
    const cardPairs: CardData[] = [];
    gameTheme.items.forEach((item, idx) => {
      const cardBase = { content: item.emoji, isFlipped: false, isMatched: false, question: item.quiz };
      cardPairs.push({ ...cardBase, id: idx * 2 });
      cardPairs.push({ ...cardBase, id: idx * 2 + 1 });
    });

    const shuffled = cardPairs.sort(() => Math.random() - 0.5);
    setCards(shuffled);
    setTheme(gameTheme);
    setScores([0, 0, 0, 0, 0]);
    setActiveTeam(0);
    setTimeLeft(INITIAL_TIME);
    setStatus(GameStatus.PLAYING);
    setFlippedIndices([]);
    startTimer();
  }, []);

  useEffect(() => {
    const loadDefault = async () => {
      setStatus(GameStatus.LOADING);
      const defaultTheme = await getThemeFromGemini("Trái cây và Động vật");
      initializeGame(defaultTheme);
    };
    loadDefault();
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [initializeGame]);

  const handleCardClick = (id: number) => {
    if (flippedIndices.length === 2 || status !== GameStatus.PLAYING) return;

    audioService.playFlip();
    const newFlipped = [...flippedIndices, id];
    setFlippedIndices(newFlipped);

    if (newFlipped.length === 2) {
      const card1 = cards.find(c => c.id === newFlipped[0]);
      const card2 = cards.find(c => c.id === newFlipped[1]);

      if (card1?.content === card2?.content) {
        setTimeout(() => {
          audioService.playMatch();
          setActiveQuestion(card1!.question || null);
          setStatus(GameStatus.QUESTION);
          setCards(prev => prev.map(c => 
            (c.id === card1!.id || c.id === card2!.id) ? { ...c, isMatched: true } : c
          ));
        }, 600);
      } else {
        setTimeout(() => {
          audioService.playWrong();
          setFlippedIndices([]);
          setActiveTeam(prev => (prev + 1) % TOTAL_TEAMS);
        }, 1200);
      }
    }
  };

  const handleAnswer = (correct: boolean) => {
    if (correct) {
      audioService.playMatch();
      setScores(prev => {
        const next = [...prev];
        next[activeTeam] += 10;
        return next;
      });
    } else {
      audioService.playWrong();
      setActiveTeam(prev => (prev + 1) % TOTAL_TEAMS);
    }

    setActiveQuestion(null);
    setStatus(GameStatus.PLAYING);
    setFlippedIndices([]);

    if (cards.every(c => c.isMatched)) {
      setStatus(GameStatus.WON);
      audioService.playVictory();
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const handleNewTheme = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() || status === GameStatus.LOADING) return;
    setStatus(GameStatus.LOADING);
    const newTheme = await getThemeFromGemini(prompt);
    initializeGame(newTheme);
    setPrompt("");
  };

  const maxScore = Math.max(...scores);

  return (
    <div className="max-w-6xl mx-auto px-4 py-6 md:py-10 min-h-screen flex flex-col font-sans">
      <header className="flex flex-col md:flex-row items-center justify-between mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className="bg-emerald-600 p-3 rounded-2xl shadow-lg">
            <i className="fa-solid fa-leaf text-white text-3xl"></i>
          </div>
          <div>
            <h1 className="text-3xl font-black text-emerald-900 leading-tight">TRÚC XANH</h1>
            <p className="text-emerald-600 text-xs font-bold tracking-widest uppercase">Vietnamese Memory Quiz • 5 Teams</p>
          </div>
        </div>

        <div className="flex items-center gap-3 bg-white px-6 py-3 rounded-2xl shadow-md border border-slate-100">
          <i className="fa-solid fa-clock text-emerald-500 animate-pulse"></i>
          <span className={`text-2xl font-mono font-bold ${timeLeft < 20 ? 'text-red-500 animate-bounce' : 'text-slate-700'}`}>
            {formatTime(timeLeft)}
          </span>
        </div>
      </header>

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start flex-grow">
        <div className="lg:col-span-3 space-y-3">
          {TEAM_COLORS.map((color, idx) => (
            <div key={idx} className={`p-4 rounded-2xl transition-all duration-300 border-2 ${
              activeTeam === idx 
              ? `${color.bg} ${color.border} ${color.shadow} scale-105 z-10 relative` 
              : 'bg-white border-slate-100 opacity-60'
            }`}>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center ${activeTeam === idx ? 'bg-white/20' : color.light}`}>
                    <i className={`fa-solid fa-user text-xs ${activeTeam === idx ? 'text-white' : color.text}`}></i>
                  </div>
                  <h3 className={`font-black text-sm ${activeTeam === idx ? 'text-white' : 'text-slate-800'}`}>ĐỘI {idx + 1}</h3>
                </div>
                <p className={`text-2xl font-black ${activeTeam === idx ? 'text-white' : color.text}`}>{scores[idx]}</p>
              </div>
            </div>
          ))}

          <form onSubmit={handleNewTheme} className="bg-white p-4 rounded-2xl shadow-xl border border-emerald-50 mt-4">
             <label className="text-xs font-bold text-slate-700 block mb-2 uppercase tracking-wider">Đổi chủ đề</label>
             <div className="flex gap-2">
                <input 
                  type="text" 
                  value={prompt}
                  onChange={e => setPrompt(e.target.value)}
                  placeholder="VD: Không gian..."
                  className="flex-grow bg-slate-50 border-none rounded-xl px-3 py-2 text-xs focus:ring-2 focus:ring-emerald-500 outline-none"
                />
                <button type="submit" className="bg-emerald-600 text-white p-2 rounded-xl hover:bg-emerald-700 transition-colors shrink-0">
                  <i className="fa-solid fa-wand-magic-sparkles text-xs"></i>
                </button>
             </div>
          </form>
        </div>

        <div className="lg:col-span-9">
          {status === GameStatus.LOADING ? (
            <div className="bg-white rounded-[2rem] aspect-square flex flex-col items-center justify-center border-4 border-emerald-100 shadow-inner">
               <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
               <p className="text-emerald-800 font-bold">AI đang chuẩn bị 5 đội...</p>
            </div>
          ) : (
            <div className="grid grid-cols-3 md:grid-cols-4 gap-3 md:gap-4 p-4 md:p-6 bg-emerald-100/30 rounded-[2rem] border-2 border-emerald-100/50 shadow-inner">
              {cards.map((card, idx) => (
                <Card 
                  key={card.id} 
                  card={{...card, isFlipped: flippedIndices.includes(card.id)}} 
                  index={idx}
                  onClick={handleCardClick}
                  disabled={status !== GameStatus.PLAYING}
                />
              ))}
            </div>
          )}
        </div>
      </main>

      {activeQuestion && <QuestionModal question={activeQuestion} onAnswer={handleAnswer} />}

      {(status === GameStatus.WON || status === GameStatus.TIME_UP) && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-lg z-[60] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] p-8 max-w-2xl w-full text-center shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-500 via-emerald-500 to-red-500"></div>
            <div className="text-6xl mb-4">🏁</div>
            <h2 className="text-3xl font-black text-slate-900 mb-2 uppercase">
              {status === GameStatus.TIME_UP ? "HẾT GIỜ!" : "TRÒ CHƠI KẾT THÚC!"}
            </h2>

            <div className="grid grid-cols-2 md:grid-cols-5 gap-3 my-6">
               {scores.map((score, idx) => (
                 <div key={idx} className={`p-4 rounded-2xl ${score === maxScore && score > 0 ? `${TEAM_COLORS[idx].light} border-2 ${TEAM_COLORS[idx].border}` : 'bg-slate-50 border-2 border-transparent'}`}>
                   <p className="text-[10px] font-bold text-slate-500 uppercase">Đội {idx + 1}</p>
                   <p className={`text-2xl font-black ${TEAM_COLORS[idx].text}`}>{score}</p>
                   {score === maxScore && score > 0 && <span className={`text-[10px] font-black ${TEAM_COLORS[idx].text} animate-bounce block mt-1`}>WIN!</span>}
                 </div>
               ))}
            </div>

            <button 
              onClick={() => theme && initializeGame(theme)}
              className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-black rounded-2xl shadow-xl transition-all active:scale-95 text-lg"
            >
              CHƠI LẠI
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

