              {card.content}
            </span>
            {card.isMatched && (
               <div className="absolute top-2 right-2">
                 <i className="fa-solid fa-circle-check text-white/80 text-xs"></i>
               </div>
            )}
          </div>
        </div>

        {/* BACK FACE (Numbered) */}
        <div className={`absolute inset-0 w-full h-full rounded-2xl shadow-lg backface-hidden border-2 overflow-hidden transition-all duration-300 group-hover:scale-105 group-hover:shadow-2xl ${
          'bg-gradient-to-br from-emerald-600 via-emerald-700 to-teal-800 border-emerald-500/50'
        }`}>
          {/* Decorative Pattern */}
          <div className="absolute inset-0 opacity-10 pointer-events-none">
            <div className="absolute top-0 left-0 w-full h-full grid grid-cols-3 gap-1 rotate-12 scale-150">
              {[...Array(9)].map((_, i) => (
                <div key={i} className="border border-white h-8 w-8 rounded-sm"></div>
              ))}
            </div>
          </div>

          <div className="card-shimmer"></div>

          <div className="relative flex flex-col items-center justify-center h-full">
            <div className="w-12 h-12 rounded-full bg-white/10 backdrop-blur-sm border border-white/20 flex items-center justify-center mb-1 group-hover:scale-110 transition-transform">
              <span className="text-white text-2xl font-black italic tracking-tighter drop-shadow-lg">
                {index + 1}
              </span>
            </div>
            <div className="flex items-center gap-1.5">
              <span className="w-1 h-1 rounded-full bg-emerald-300/60"></span>
              <span className="text-white/40 font-extrabold text-[8px] tracking-[0.2em] uppercase">TRÚC XANH</span>
