  IDLE = 'IDLE',
  LOADING = 'LOADING',
  PLAYING = 'PLAYING',
  QUESTION = 'QUESTION',
  WON = 'WON'
}

export interface GameTheme {
  name: string;
  items: {
    emoji: string;
    quiz: QuizQuestion;
  }[];
}

