                  <div className="flex items-center justify-between relative z-10">
                    <div className="flex items-center gap-3">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${isActive ? 'bg-white/20 scale-110' : `${color.light} ${color.text}`}`}>
                        <i className={`fa-solid ${color.icon} text-lg`}></i>
                      </div>
                      <div>
                        <h3 className={`font-extrabold text-sm tracking-tight ${isActive ? 'text-white' : 'text-slate-800'}`}>ĐỘI {idx + 1}</h3>
                        <p className={`text-[10px] font-bold ${isActive ? 'text-white/70' : 'text-slate-400'} uppercase tracking-widest`}>Player Group</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className={`text-3xl font-black ${isActive ? 'text-white' : color.text}`}>{scores[idx]}</p>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          <form onSubmit={handleNewTheme} className="glass-panel p-6 rounded-[2rem] shadow-xl mt-6">
             <div className="flex items-center gap-2 mb-4">
                <i className="fa-solid fa-wand-magic-sparkles text-emerald-500"></i>
                <label className="text-xs font-black text-slate-800 uppercase tracking-[0.2em]">Generate Theme</label>
             </div>
             <div className="flex gap-2">
                <input 
                  type="text" 
                  value={prompt}
                  onChange={e => setPrompt(e.target.value)}
                  placeholder="Space, Animals, Foods..."
                  className="flex-grow bg-slate-100/50 border-none rounded-2xl px-5 py-3 text-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all placeholder:text-slate-400 font-semibold"
                />
                <button type="submit" className="bg-emerald-600 text-white w-12 h-12 rounded-2xl hover:bg-emerald-700 transition-all shadow-lg flex items-center justify-center shrink-0 active:scale-90">
                  <i className="fa-solid fa-plus"></i>
                </button>
             </div>
          </form>
        </div>

        {/* Game Board */}
        <div className="lg:col-span-9">
          {status === GameStatus.LOADING ? (
            <div className="bg-white/50 backdrop-blur-md rounded-[3rem] aspect-square lg:aspect-video flex flex-col items-center justify-center border-4 border-dashed border-emerald-200 shadow-inner">
               <div className="relative">
                 <div className="w-24 h-24 border-8 border-emerald-100 border-t-emerald-600 rounded-full animate-spin mb-8"></div>
                 <i className="fa-solid fa-brain text-emerald-600 text-2xl absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-12"></i>
               </div>
               <p className="text-emerald-900 text-2xl font-black tracking-tight animate-pulse">Sắp xếp mê cung thẻ bài...</p>
               <p className="text-slate-400 text-sm mt-3 font-semibold uppercase tracking-[0.3em]">AI is thinking</p>
            </div>
          ) : (
            <div className="relative">
              <div className="grid grid-cols-3 md:grid-cols-4 gap-4 md:gap-6 p-6 md:p-10 glass-panel rounded-[3rem] shadow-2xl">
                {cards.map((card, idx) => (
                  <Card 
                    key={card.id} 
                    card={{...card, isFlipped: flippedIndices.includes(card.id)}} 
                    index={idx}
                    onClick={handleCardClick}
                    disabled={status !== GameStatus.PLAYING}
                  />
                ))}
              </div>

              {/* Decorative elements around the board */}
              <div className="absolute -top-6 -right-6 w-24 h-24 bg-yellow-400/20 blur-3xl rounded-full"></div>
              <div className="absolute -bottom-10 -left-10 w-40 h-40 bg-emerald-400/20 blur-[80px] rounded-full"></div>
            </div>
          )}
        </div>
      </main>

      {/* Quiz Modal */}
      {activeQuestion && <QuestionModal question={activeQuestion} onAnswer={handleAnswer} />}

      {/* Victory/End Overlay */}
      {status === GameStatus.WON && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[60] flex items-center justify-center p-6">
          <div className="bg-white rounded-[4rem] p-10 max-w-4xl w-full text-center shadow-[0_32px_64px_-12px_rgba(0,0,0,0.5)] relative overflow-hidden animate-in zoom-in duration-500">
            <div className="absolute top-0 left-0 w-full h-3 bg-gradient-to-r from-blue-500 via-emerald-500 to-rose-500"></div>

            <div className="relative z-10">
              <div className="text-8xl mb-8 animate-bounce">🏆</div>
              <h2 className="text-5xl font-black text-slate-900 mb-2 tracking-tight">
                CHIẾN THẮNG!
              </h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest mb-10">Final Rankings</p>

              <div className="grid grid-cols-1 md:grid-cols-5 gap-4 mb-12">
                 {scores.map((score, idx) => {
                   const isWinner = score === maxScore && score > 0;
                   return (
                     <div key={idx} className={`p-6 rounded-[2rem] transition-all transform ${isWinner ? `scale-110 ${TEAM_COLORS[idx].light} border-4 ${TEAM_COLORS[idx].border} shadow-2xl` : 'bg-slate-50 border-2 border-slate-100 opacity-60'}`}>
                       <p className="text-xs font-black text-slate-400 uppercase mb-2">Đội {idx + 1}</p>
                       <p className={`text-4xl font-black ${TEAM_COLORS[idx].text}`}>{score}</p>
                       {isWinner && (
                         <div className="mt-3 flex flex-col items-center">
                            <span className={`text-[10px] font-black ${TEAM_COLORS[idx].text} uppercase tracking-tighter`}>Grand Champion</span>
                            <div className="flex gap-1 mt-1">
                               {[...Array(3)].map((_, i) => <i key={i} className={`fa-solid fa-star text-[8px] ${TEAM_COLORS[idx].text}`}></i>)}
                            </div>
                         </div>
                       )}
                     </div>
                   );
                 })}
              </div>

              <button 
                onClick={() => theme && initializeGame(theme)}
                className="group relative inline-flex items-center justify-center px-12 py-5 font-black text-white transition-all duration-200 bg-emerald-600 rounded-3xl hover:bg-emerald-700 active:scale-95 shadow-xl shadow-emerald-600/30 overflow-hidden"
              >
                <span className="relative z-10 text-xl flex items-center gap-3">
                   <i className="fa-solid fa-rotate-right"></i>
                   CHƠI LẠI NGAY
                </span>
                <div className="absolute inset-0 bg-white/10 translate-x-[-100%] group-hover:translate-x-0 transition-transform duration-500 skew-x-12"></div>
              </button>
            </div>

            {/* Background elements in modal */}
            <div className="absolute -bottom-20 -left-20 w-64 h-64 bg-emerald-100 rounded-full opacity-50 blur-3xl"></div>
            <div className="absolute -top-20 -right-20 w-64 h-64 bg-blue-100 rounded-full opacity-50 blur-3xl"></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export interface QuizQuestion {
  question: string;
  options: string[];
  correctAnswer: string;
}

export interface CardData {
  id: number;
  content: string;
  isFlipped: boolean;
  isMatched: boolean;
  question?: QuizQuestion;
}

export enum GameStatus {
  IDLE = 'IDLE',
  SETUP = 'SETUP',
  LOADING = 'LOADING',
  PLAYING = 'PLAYING',
  QUESTION = 'QUESTION',
  WON = 'WON'
}

export interface GameTheme {
  name: string;
  items: {
    emoji: string;
    quiz: QuizQuestion;
  }[];
}

import React, { useState } from 'react';
import { GameTheme, QuizQuestion } from '../types';
import { getThemeFromGemini } from '../services/geminiService';

interface SetupScreenProps {
  onComplete: (theme: GameTheme) => void;
  onLoading: () => void;
}

export const SetupScreen: React.FC<SetupScreenProps> = ({ onComplete, onLoading }) => {
  const [mode, setMode] = useState<'CHOICE' | 'AI' | 'MANUAL'>('CHOICE');
  const [prompt, setPrompt] = useState('');
  const [manualTheme, setManualTheme] = useState<GameTheme>({
    name: 'Chủ đề của tôi',
    items: Array(6).fill(null).map(() => ({
      emoji: '⭐',
      quiz: { question: '', options: ['', '', '', ''], correctAnswer: '' }
    }))
  });

  const handleAiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;
    onLoading();
    const theme = await getThemeFromGemini(prompt);
    onComplete(theme);
  };

  const handleManualItemChange = (idx: number, field: string, value: any) => {
    const newItems = [...manualTheme.items];
    if (field === 'emoji') newItems[idx].emoji = value;
    else if (field === 'question') newItems[idx].quiz.question = value;
    else if (field === 'correctAnswer') newItems[idx].quiz.correctAnswer = value;
    setManualTheme({ ...manualTheme, items: newItems });
  };

  const handleOptionChange = (itemIdx: number, optIdx: number, value: string) => {
    const newItems = [...manualTheme.items];
    newItems[itemIdx].quiz.options[optIdx] = value;
    setManualTheme({ ...manualTheme, items: newItems });
  };

  const validateManual = () => {
    return manualTheme.items.every(item => 
      item.emoji && item.quiz.question && 
      item.quiz.options.every(o => o) && 
      item.quiz.options.includes(item.quiz.correctAnswer)
    );
  };

  if (mode === 'CHOICE') {
    return (
      <div className="max-w-4xl mx-auto py-20 px-4 text-center animate-in fade-in slide-in-from-bottom-4 duration-700">
        <h2 className="text-5xl font-black text-emerald-900 mb-6 tracking-tight">Thiết Lập Trò Chơi</h2>
        <p className="text-slate-500 text-lg mb-12 font-medium">Chọn cách bạn muốn chuẩn bị câu hỏi cho học sinh</p>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <button 
            onClick={() => setMode('AI')}
            className="group p-10 bg-white rounded-[3rem] border-4 border-emerald-100 hover:border-emerald-500 transition-all shadow-xl hover:shadow-emerald-200/50 flex flex-col items-center gap-6"
          >
            <div className="w-24 h-24 bg-emerald-100 rounded-full flex items-center justify-center group-hover:scale-110 transition-transform">
              <i className="fa-solid fa-wand-magic-sparkles text-4xl text-emerald-600"></i>
            </div>
            <div className="text-center">
              <h3 className="text-2xl font-bold text-slate-800 mb-2">Tạo Bằng AI</h3>
              <p className="text-slate-400 text-sm">Chỉ cần nhập chủ đề, Gemini sẽ tự soạn 6 câu hỏi và emoji sinh động.</p>
            </div>
          </button>

          <button 
            onClick={() => setMode('MANUAL')}
            className="group p-10 bg-white rounded-[3rem] border-4 border-blue-100 hover:border-blue-500 transition-all shadow-xl hover:shadow-blue-200/50 flex flex-col items-center gap-6"
          >
            <div className="w-24 h-24 bg-blue-100 rounded-full flex items-center justify-center group-hover:scale-110 transition-transform">
              <i className="fa-solid fa-pen-to-square text-4xl text-blue-600"></i>
            </div>
            <div className="text-center">
              <h3 className="text-2xl font-bold text-slate-800 mb-2">Nhập Thủ Công</h3>
              <p className="text-slate-400 text-sm">Giáo viên tự soạn nội dung câu hỏi và chọn emoji theo ý muốn.</p>
            </div>
          </button>
        </div>
      </div>
    );
  }

  if (mode === 'AI') {
    return (
      <div className="max-w-2xl mx-auto py-20 px-4 animate-in zoom-in duration-500">
        <button onClick={() => setMode('CHOICE')} className="mb-8 text-slate-400 hover:text-emerald-600 font-bold flex items-center gap-2">
          <i className="fa-solid fa-arrow-left"></i> Quay lại
        </button>
        <div className="glass-panel p-10 rounded-[3rem] shadow-2xl">
          <h3 className="text-3xl font-black text-slate-800 mb-6">Chủ Đề Trò Chơi</h3>
          <form onSubmit={handleAiSubmit} className="space-y-6">
            <input 
              autoFocus
              value={prompt}
              onChange={e => setPrompt(e.target.value)}
              placeholder="Ví dụ: Động vật biển, Các hành tinh, Trái cây nhiệt đới..."
              className="w-full bg-slate-100/50 border-none rounded-2xl px-6 py-4 text-lg font-semibold focus:ring-4 focus:ring-emerald-500/20 outline-none transition-all"
            />
            <button className="w-full py-5 bg-emerald-600 text-white rounded-2xl font-black text-xl shadow-lg hover:bg-emerald-700 active:scale-95 transition-all">
              TẠO CÂU HỎI NGAY
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto py-10 px-4 animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-8">
        <button onClick={() => setMode('CHOICE')} className="text-slate-400 hover:text-blue-600 font-bold flex items-center gap-2">
          <i className="fa-solid fa-arrow-left"></i> Quay lại
        </button>
        <h3 className="text-3xl font-black text-slate-800">Soạn 6 Cặp Câu Hỏi</h3>
        <button 
          onClick={() => validateManual() && onComplete(manualTheme)}
          disabled={!validateManual()}
          className="px-10 py-4 bg-blue-600 text-white rounded-2xl font-black shadow-lg hover:bg-blue-700 disabled:bg-slate-300 disabled:cursor-not-allowed transition-all"
        >
          BẮT ĐẦU CHƠI
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {manualTheme.items.map((item, idx) => (
          <div key={idx} className="bg-white p-6 rounded-[2rem] shadow-lg border-2 border-slate-100 relative">
            <div className="absolute top-4 right-6 text-slate-300 font-black text-2xl">#0{idx+1}</div>

            <div className="mb-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Biểu tượng (Emoji)</label>
              <input 
                value={item.emoji}
                onChange={e => handleManualItemChange(idx, 'emoji', e.target.value)}
                className="w-12 h-12 text-2xl text-center bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-blue-500"
              />
            </div>

            <div className="mb-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Câu hỏi</label>
              <textarea 
                value={item.quiz.question}
                onChange={e => handleManualItemChange(idx, 'question', e.target.value)}
                rows={2}
                className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 text-sm font-semibold focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Nhập câu hỏi đố vui..."
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Đáp án (Chọn đúng)</label>
              {item.quiz.options.map((opt, oIdx) => (
                <div key={oIdx} className="flex gap-2 items-center">
                  <input 
                    type="radio"
                    name={`correct-${idx}`}
                    checked={item.quiz.correctAnswer === opt && opt !== ''}
                    onChange={() => handleManualItemChange(idx, 'correctAnswer', opt)}
                    className="w-4 h-4 text-blue-600"
                  />
                  <input 
                    value={opt}
                    onChange={e => handleOptionChange(idx, oIdx, e.target.value)}
                    className="flex-grow bg-slate-50 border-none rounded-lg px-3 py-1.5 text-xs font-medium focus:ring-2 focus:ring-blue-500"
                    placeholder={`Lựa chọn ${String.fromCharCode(65+oIdx)}...`}
                  />
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { CardData, GameStatus, GameTheme, QuizQuestion } from './types';
import { audioService } from './services/audioService';
import { Card } from './components/Card';
import { QuestionModal } from './components/QuestionModal';
import { SetupScreen } from './components/SetupScreen';

const TOTAL_TEAMS = 5;

const TEAM_COLORS = [
  { bg: 'from-blue-500 to-indigo-600', border: 'border-blue-400', shadow: 'shadow-blue-500/40', text: 'text-blue-600', light: 'bg-blue-50', icon: 'fa-dragon' },
  { bg: 'from-rose-500 to-red-600', border: 'border-rose-400', shadow: 'shadow-rose-500/40', text: 'text-rose-600', light: 'bg-rose-50', icon: 'fa-fire' },
  { bg: 'from-amber-400 to-orange-500', border: 'border-amber-400', shadow: 'shadow-amber-500/40', text: 'text-amber-600', light: 'bg-amber-50', icon: 'fa-bolt' },
  { bg: 'from-fuchsia-500 to-purple-600', border: 'border-fuchsia-400', shadow: 'shadow-fuchsia-500/40', text: 'text-fuchsia-600', light: 'bg-fuchsia-50', icon: 'fa-star' },
  { bg: 'from-teal-400 to-cyan-600', border: 'border-teal-400', shadow: 'shadow-teal-500/40', text: 'text-teal-600', light: 'bg-teal-50', icon: 'fa-leaf' },
];

const App: React.FC = () => {
  const [theme, setTheme] = useState<GameTheme | null>(null);
  const [cards, setCards] = useState<CardData[]>([]);
  const [flippedIndices, setFlippedIndices] = useState<number[]>([]);
  const [status, setStatus] = useState<GameStatus>(GameStatus.SETUP);
  const [activeTeam, setActiveTeam] = useState(0); // 0 to 4
  const [scores, setScores] = useState([0, 0, 0, 0, 0]);
  const [activeQuestion, setActiveQuestion] = useState<QuizQuestion | null>(null);

  const initializeGame = useCallback(async (gameTheme: GameTheme) => {
    const cardPairs: CardData[] = [];
    gameTheme.items.forEach((item, idx) => {
      const cardBase = { content: item.emoji, isFlipped: false, isMatched: false, question: item.quiz };
      cardPairs.push({ ...cardBase, id: idx * 2 });
      cardPairs.push({ ...cardBase, id: idx * 2 + 1 });
    });

    const shuffled = cardPairs.sort(() => Math.random() - 0.5);
    setCards(shuffled);
    setTheme(gameTheme);
    setScores([0, 0, 0, 0, 0]);
    setActiveTeam(0);
    setStatus(GameStatus.PLAYING);
    setFlippedIndices([]);
  }, []);

  const handleCardClick = (id: number) => {
    if (flippedIndices.length === 2 || status !== GameStatus.PLAYING) return;

    audioService.playFlip();
    const newFlipped = [...flippedIndices, id];
    setFlippedIndices(newFlipped);

    if (newFlipped.length === 2) {
      const card1 = cards.find(c => c.id === newFlipped[0]);
      const card2 = cards.find(c => c.id === newFlipped[1]);

      if (card1?.content === card2?.content) {
        setTimeout(() => {
          audioService.playMatch();
          setActiveQuestion(card1!.question || null);
          setStatus(GameStatus.QUESTION);
          setCards(prev => prev.map(c => 
            (c.id === card1!.id || c.id === card2!.id) ? { ...c, isMatched: true } : c
          ));
        }, 600);
      } else {
        setTimeout(() => {
          audioService.playWrong();
          setFlippedIndices([]);
          setActiveTeam(prev => (prev + 1) % TOTAL_TEAMS);
        }, 1200);
      }
    }
  };

  const handleAnswer = (correct: boolean) => {
    if (correct) {
      audioService.playMatch();
      setScores(prev => {
        const next = [...prev];
        next[activeTeam] += 10;
        return next;
      });
    } else {
      audioService.playWrong();
      setActiveTeam(prev => (prev + 1) % TOTAL_TEAMS);
    }

    setActiveQuestion(null);
    setStatus(GameStatus.PLAYING);
    setFlippedIndices([]);

    if (cards.every(c => c.isMatched)) {
      setStatus(GameStatus.WON);
      audioService.playVictory();
    }
  };

  const maxScore = Math.max(...scores);

  const handleNewGameClick = () => {
    setStatus(GameStatus.SETUP);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-6 md:py-10 min-h-screen flex flex-col font-sans">
      {/* Header */}
      <header className="flex flex-col md:flex-row items-center justify-between mb-10 gap-6">
        <div className="flex items-center gap-5">
          <div className="bg-gradient-to-br from-emerald-500 to-teal-700 p-4 rounded-3xl shadow-2xl animate-float">
            <i className="fa-solid fa-leaf text-white text-4xl"></i>
          </div>
          <div>
            <h1 className="text-4xl font-extrabold text-emerald-900 leading-none tracking-tight">TRÚC XANH</h1>
            <div className="flex items-center gap-2 mt-2">
               <span className="px-2 py-0.5 bg-emerald-100 text-emerald-700 text-[10px] font-bold rounded-full uppercase">Tournament Mode</span>
               <div className="h-1 w-1 rounded-full bg-slate-300"></div>
               <p className="text-slate-500 text-xs font-semibold uppercase tracking-wider">5 Teams Competition</p>
            </div>
          </div>
        </div>

        {status !== GameStatus.SETUP && status !== GameStatus.LOADING && (
          <button 
            onClick={handleNewGameClick}
            className="flex items-center gap-3 px-6 py-3 bg-white text-emerald-600 rounded-2xl font-black shadow-md hover:shadow-xl hover:scale-105 transition-all border border-emerald-100 group"
          >
            <i className="fa-solid fa-rotate-right group-hover:rotate-180 transition-transform duration-500"></i>
            BẮT ĐẦU VÁN MỚI
          </button>
        )}
      </header>

      {status === GameStatus.SETUP && (
        <SetupScreen 
          onComplete={initializeGame} 
          onLoading={() => setStatus(GameStatus.LOADING)} 
        />
      )}

      {status === GameStatus.LOADING && (
        <div className="bg-white/50 backdrop-blur-md rounded-[3rem] aspect-square lg:aspect-video flex flex-col items-center justify-center border-4 border-dashed border-emerald-200 shadow-inner flex-grow">
           <div className="relative">
             <div className="w-24 h-24 border-8 border-emerald-100 border-t-emerald-600 rounded-full animate-spin mb-8"></div>
             <i className="fa-solid fa-brain text-emerald-600 text-2xl absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-12"></i>
           </div>
           <p className="text-emerald-900 text-2xl font-black tracking-tight animate-pulse">Đang thiết lập mê cung...</p>
           <p className="text-slate-400 text-sm mt-3 font-semibold uppercase tracking-[0.3em]">Preparing Game Content</p>
        </div>
      )}

      {(status === GameStatus.PLAYING || status === GameStatus.QUESTION || status === GameStatus.WON) && (
        <main className="grid grid-cols-1 lg:grid-cols-12 gap-10 items-start flex-grow animate-in fade-in duration-700">
          {/* Left Sidebar: Teams */}
          <div className="lg:col-span-3 space-y-4">
            <div className="space-y-3">
              {TEAM_COLORS.map((color, idx) => {
                const isActive = activeTeam === idx;
                return (
                  <div key={idx} className={`p-5 rounded-3xl transition-all duration-500 border-2 overflow-hidden relative group ${
                    isActive 
                    ? `bg-gradient-to-r ${color.bg} ${color.border} shadow-2xl ${color.shadow} scale-105 z-10` 
                    : 'bg-white border-slate-100/50 opacity-70 hover:opacity-100 grayscale hover:grayscale-0'
                  }`}>
                    {isActive && (
                      <div className="absolute top-0 right-0 p-1 bg-white/20 rounded-bl-xl">
                        <i className="fa-solid fa-play text-[8px] text-white animate-pulse"></i>
                      </div>
                    )}

                    <div className="flex items-center justify-between relative z-10">
                      <div className="flex items-center gap-3">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all ${isActive ? 'bg-white/20 scale-110' : `${color.light} ${color.text}`}`}>
                          <i className={`fa-solid ${color.icon} text-lg`}></i>
                        </div>
                        <div>
                          <h3 className={`font-extrabold text-sm tracking-tight ${isActive ? 'text-white' : 'text-slate-800'}`}>ĐỘI {idx + 1}</h3>
                          <p className={`text-[10px] font-bold ${isActive ? 'text-white/70' : 'text-slate-400'} uppercase tracking-widest`}>Player Group</p>
                        </div>
                      </div>
                      <div className="text-right">
                        <p className={`text-3xl font-black ${isActive ? 'text-white' : color.text}`}>{scores[idx]}</p>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>

            <div className="glass-panel p-6 rounded-[2rem] shadow-xl mt-6 border-2 border-emerald-100">
               <div className="flex items-center gap-2 mb-2">
                  <i className="fa-solid fa-tag text-emerald-500"></i>
                  <label className="text-[10px] font-black text-slate-800 uppercase tracking-[0.2em]">Chủ đề hiện tại</label>
               </div>
               <p className="text-xl font-bold text-emerald-900 truncate">{theme?.name}</p>
            </div>
          </div>

          {/* Game Board */}
          <div className="lg:col-span-9">
            <div className="relative">
              <div className="grid grid-cols-3 md:grid-cols-4 gap-4 md:gap-6 p-6 md:p-10 glass-panel rounded-[3rem] shadow-2xl">
                {cards.map((card, idx) => (
                  <Card 
                    key={card.id} 
                    card={{...card, isFlipped: flippedIndices.includes(card.id)}} 
                    index={idx}
                    onClick={handleCardClick}
                    disabled={status !== GameStatus.PLAYING}
                  />
                ))}
              </div>
              <div className="absolute -top-6 -right-6 w-24 h-24 bg-yellow-400/20 blur-3xl rounded-full"></div>
              <div className="absolute -bottom-10 -left-10 w-40 h-40 bg-emerald-400/20 blur-[80px] rounded-full"></div>
            </div>
          </div>
        </main>
      )}

      {/* Quiz Modal */}
      {activeQuestion && <QuestionModal question={activeQuestion} onAnswer={handleAnswer} />}

      {/* Victory Overlay */}
      {status === GameStatus.WON && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[60] flex items-center justify-center p-6">
          <div className="bg-white rounded-[4rem] p-10 max-w-4xl w-full text-center shadow-[0_32px_64px_-12px_rgba(0,0,0,0.5)] relative overflow-hidden animate-in zoom-in duration-500">
            <div className="absolute top-0 left-0 w-full h-3 bg-gradient-to-r from-blue-500 via-emerald-500 to-rose-500"></div>
            <div className="relative z-10">
              <div className="text-8xl mb-8 animate-bounce">🏆</div>
              <h2 className="text-5xl font-black text-slate-900 mb-2 tracking-tight uppercase">CHIẾN THẮNG!</h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest mb-10">Bảng Xếp Hạng Cuối Cùng</p>

              <div className="grid grid-cols-1 md:grid-cols-5 gap-4 mb-12">
                 {scores.map((score, idx) => {
                   const isWinner = score === maxScore && score > 0;
                   return (
                     <div key={idx} className={`p-6 rounded-[2rem] transition-all transform ${isWinner ? `scale-110 ${TEAM_COLORS[idx].light} border-4 ${TEAM_COLORS[idx].border} shadow-2xl` : 'bg-slate-50 border-2 border-slate-100 opacity-60'}`}>
                       <p className="text-xs font-black text-slate-400 uppercase mb-2">Đội {idx + 1}</p>
                       <p className={`text-4xl font-black ${TEAM_COLORS[idx].text}`}>{score}</p>
                       {isWinner && (
                         <div className="mt-3 flex flex-col items-center">
                            <span className={`text-[10px] font-black ${TEAM_COLORS[idx].text} uppercase tracking-tighter`}>Vô Địch</span>
                         </div>
                       )}
                     </div>
                   );
                 })}
              </div>

              <button 
                onClick={handleNewGameClick}
                className="group relative inline-flex items-center justify-center px-12 py-5 font-black text-white transition-all duration-200 bg-emerald-600 rounded-3xl hover:bg-emerald-700 active:scale-95 shadow-xl shadow-emerald-600/30 overflow-hidden"
              >
                <span className="relative z-10 text-xl flex items-center gap-3">
                   <i className="fa-solid fa-rotate-right"></i>
                   CHƠI LẠI VỚI CHỦ ĐỀ MỚI
                </span>
                <div className="absolute inset-0 bg-white/10 translate-x-[-100%] group-hover:translate-x-0 transition-transform duration-500 skew-x-12"></div>
              </button>
            </div>
            <div className="absolute -bottom-20 -left-20 w-64 h-64 bg-emerald-100 rounded-full opacity-50 blur-3xl"></div>
            <div className="absolute -top-20 -right-20 w-64 h-64 bg-blue-100 rounded-full opacity-50 blur-3xl"></div>
          </div>
        </div>
      )}
    </div>
  );
};

