import React, { useState } from 'react';
import { GameTheme, QuizQuestion } from '../types';
import { getThemeFromGemini } from '../services/geminiService';

interface SetupScreenProps {
  onComplete: (theme: GameTheme) => void;
  onLoading: () => void;
}

export const SetupScreen: React.FC<SetupScreenProps> = ({ onComplete, onLoading }) => {
  const [mode, setMode] = useState<'CHOICE' | 'AI' | 'MANUAL'>('CHOICE');
  const [prompt, setPrompt] = useState('');
  const [manualTheme, setManualTheme] = useState<GameTheme>({
    name: 'Chủ đề tùy chỉnh',
    items: Array(6).fill(null).map(() => ({
      emoji: '⭐',
      quiz: { question: '', options: ['', '', '', ''], correctAnswer: '' }
    }))
  });

  const handleAiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;
    onLoading();
    const theme = await getThemeFromGemini(userPromptWithMathInstruction(prompt));
    onComplete(theme);
  };

  const userPromptWithMathInstruction = (p: string) => 
    `${p}. Lưu ý: Nếu có công thức toán học, hãy sử dụng định dạng LaTeX (ví dụ: $x^2 + y^2 = r^2$) để hiển thị đẹp mắt.`;

  const handleManualItemChange = (idx: number, field: string, value: any) => {
    const newItems = [...manualTheme.items];
    if (field === 'emoji') newItems[idx].emoji = value;
    else if (field === 'question') newItems[idx].quiz.question = value;
    else if (field === 'correctAnswer') newItems[idx].quiz.correctAnswer = value;
    setManualTheme({ ...manualTheme, items: newItems });
  };

  const handleOptionChange = (itemIdx: number, optIdx: number, value: string) => {
    const newItems = [...manualTheme.items];
    newItems[itemIdx].quiz.options[optIdx] = value;
    setManualTheme({ ...manualTheme, items: newItems });
  };

  const validateManual = () => {
    return manualTheme.items.every(item => 
      item.emoji && item.quiz.question && 
      item.quiz.options.every(o => o) && 
      item.quiz.options.includes(item.quiz.correctAnswer)
    );
  };

  if (mode === 'CHOICE') {
    return (
      <div className="max-w-5xl mx-auto py-20 px-4 text-center animate-in fade-in slide-in-from-bottom-8 duration-1000">
        <div className="inline-block p-4 bg-emerald-100 rounded-3xl mb-8 animate-float">
          <i className="fa-solid fa-gamepad text-5xl text-emerald-600"></i>
        </div>
        <h2 className="text-6xl font-black text-slate-900 mb-6 tracking-tight">Chuẩn Bị Cuộc Đua</h2>
        <p className="text-slate-500 text-xl mb-16 font-medium max-w-2xl mx-auto leading-relaxed">
          Chào mừng Giáo viên! Hãy chọn cách thức để tạo ra những thử thách thú vị cho 5 đội chơi hôm nay.
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <button 
            onClick={() => setMode('AI')}
            className="group relative p-12 bg-white rounded-[4rem] border-4 border-emerald-100 hover:border-emerald-500 transition-all shadow-[0_20px_50px_-15px_rgba(0,0,0,0.1)] hover:shadow-emerald-200/50 flex flex-col items-center gap-8 overflow-hidden active:scale-95"
          >
            <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50 rounded-bl-[100%] transition-all group-hover:scale-150"></div>
            <div className="w-24 h-24 bg-gradient-to-br from-emerald-500 to-teal-600 rounded-[2rem] flex items-center justify-center shadow-lg group-hover:rotate-6 transition-all duration-500">
              <i className="fa-solid fa-wand-magic-sparkles text-4xl text-white"></i>
            </div>
            <div className="text-center relative z-10">
              <h3 className="text-3xl font-black text-slate-800 mb-3">Thông Minh Với AI</h3>
              <p className="text-slate-400 font-bold leading-relaxed">Nhập chủ đề bất kỳ, Gemini sẽ tự động soạn thảo nội dung chuyên nghiệp kèm theo biểu tượng.</p>
            </div>
          </button>

          <button 
            onClick={() => setMode('MANUAL')}
            className="group relative p-12 bg-white rounded-[4rem] border-4 border-indigo-100 hover:border-indigo-500 transition-all shadow-[0_20px_50px_-15px_rgba(0,0,0,0.1)] hover:shadow-indigo-200/50 flex flex-col items-center gap-8 overflow-hidden active:scale-95"
          >
            <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50 rounded-bl-[100%] transition-all group-hover:scale-150"></div>
            <div className="w-24 h-24 bg-gradient-to-br from-indigo-500 to-blue-600 rounded-[2rem] flex items-center justify-center shadow-lg group-hover:rotate-6 transition-all duration-500">
              <i className="fa-solid fa-pen-nib text-4xl text-white"></i>
            </div>
            <div className="text-center relative z-10">
              <h3 className="text-3xl font-black text-slate-800 mb-3">Tự Do Sáng Tạo</h3>
              <p className="text-slate-400 font-bold leading-relaxed">Giáo viên hoàn toàn làm chủ nội dung, câu hỏi và đáp án cho phù hợp với bài học.</p>
            </div>
          </button>
        </div>
      </div>
    );
  }

  if (mode === 'AI') {
    return (
      <div className="max-w-3xl mx-auto py-20 px-4 animate-in zoom-in duration-500">
        <button onClick={() => setMode('CHOICE')} className="mb-10 text-emerald-600 hover:text-emerald-800 font-black flex items-center gap-3 transition-colors text-lg">
          <i className="fa-solid fa-circle-chevron-left"></i> Quay lại
        </button>
        <div className="glass-panel p-16 rounded-[4rem] shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-emerald-500"></div>
          <h3 className="text-4xl font-black text-slate-900 mb-8 tracking-tight">Chủ Đề Mong Muốn?</h3>
          <form onSubmit={handleAiSubmit} className="space-y-10">
            <div className="relative">
              <input 
                autoFocus
                value={prompt}
                onChange={e => setPrompt(e.target.value)}
                placeholder="Ví dụ: Đại số lớp 9, Sinh học 12..."
                className="w-full bg-slate-100/50 border-4 border-transparent focus:border-emerald-100 rounded-3xl px-8 py-6 text-xl font-bold focus:ring-0 outline-none transition-all placeholder:text-slate-300"
              />
              <div className="absolute right-6 top-1/2 -translate-y-1/2 opacity-20 text-3xl">
                <i className="fa-solid fa-keyboard"></i>
              </div>
            </div>
            <div className="bg-emerald-50 p-6 rounded-3xl flex items-center gap-4 border-2 border-emerald-100">
              <i className="fa-solid fa-circle-info text-emerald-500 text-xl"></i>
              <p className="text-sm font-bold text-emerald-800 italic">Hệ thống hỗ trợ hiển thị ký hiệu toán học qua LaTeX.</p>
            </div>
            <button className="w-full py-6 bg-emerald-600 text-white rounded-3xl font-black text-2xl shadow-[0_15px_30px_-5px_rgba(16,185,129,0.4)] hover:bg-emerald-700 active:scale-95 transition-all flex items-center justify-center gap-4">
              XÂY DỰNG TRÒ CHƠI <i className="fa-solid fa-bolt"></i>
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto py-10 px-4 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row items-center justify-between mb-12 gap-6 bg-white p-8 rounded-[3rem] shadow-lg border-2 border-slate-50">
        <div className="flex items-center gap-6">
          <button onClick={() => setMode('CHOICE')} className="w-14 h-14 bg-slate-100 rounded-2xl text-slate-500 hover:bg-slate-200 flex items-center justify-center transition-all">
            <i className="fa-solid fa-arrow-left text-xl"></i>
          </button>
          <div>
            <h3 className="text-3xl font-black text-slate-800 tracking-tight">Bảng Soạn Thảo Thủ Công</h3>
            <p className="text-indigo-500 font-black uppercase text-[10px] tracking-widest mt-1">Sử dụng $...$ cho LaTeX (Ví dụ: $a^2+b^2=c^2$)</p>
          </div>
        </div>
        <button 
          onClick={() => validateManual() && onComplete(manualTheme)}
          disabled={!validateManual()}
          className="px-12 py-5 bg-indigo-600 text-white rounded-3xl font-black text-xl shadow-xl hover:bg-indigo-700 disabled:bg-slate-200 disabled:text-slate-400 disabled:shadow-none disabled:cursor-not-allowed transition-all flex items-center gap-4"
        >
          XÁC NHẬN & CHƠI <i className="fa-solid fa-circle-check"></i>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {manualTheme.items.map((item, idx) => (
          <div key={idx} className="bg-white p-10 rounded-[4rem] shadow-xl border-4 border-slate-50 relative group hover:border-indigo-100 transition-all">
            <div className="absolute top-6 right-10 text-slate-100 group-hover:text-indigo-50 font-black text-6xl transition-colors">0{idx+1}</div>

            <div className="mb-8 relative z-10">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Emoji Nhận Diện</label>
              <input 
                value={item.emoji}
                onChange={e => handleManualItemChange(idx, 'emoji', e.target.value)}
                className="w-20 h-20 text-4xl text-center bg-slate-50 border-4 border-transparent focus:border-indigo-100 rounded-[2rem] focus:ring-0 outline-none transition-all shadow-inner"
                placeholder="⭐"
              />
            </div>

            <div className="mb-8 relative z-10">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Nội dung Câu hỏi</label>
              <textarea 
                value={item.quiz.question}
                onChange={e => handleManualItemChange(idx, 'question', e.target.value)}
                rows={3}
                className="w-full bg-slate-50 border-4 border-transparent focus:border-indigo-100 rounded-3xl px-6 py-5 text-sm font-bold focus:ring-0 outline-none transition-all shadow-inner"
                placeholder="Câu hỏi kèm LaTeX nếu cần..."
              />
            </div>

            <div className="space-y-3 relative z-10">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Lựa chọn & Đáp án đúng</label>
              {item.quiz.options.map((opt, oIdx) => (
                <div key={oIdx} className="flex gap-3 items-center group/opt">
                  <div className="relative">
                    <input 
                      type="radio"
                      name={`correct-${idx}`}
                      checked={item.quiz.correctAnswer === opt && opt !== ''}
                      onChange={() => handleManualItemChange(idx, 'correctAnswer', opt)}
                      className="w-6 h-6 text-indigo-600 border-2 border-slate-200 focus:ring-0 rounded-full cursor-pointer"
                    />
                  </div>
                  <input 
                    value={opt}
                    onChange={e => handleOptionChange(idx, oIdx, e.target.value)}
                    className="flex-grow bg-slate-50 border-2 border-transparent focus:border-indigo-50 rounded-2xl px-5 py-3 text-xs font-bold focus:ring-0 outline-none transition-all shadow-sm"
                    placeholder={`Lựa chọn ${String.fromCharCode(65+oIdx)}...`}
                  />
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

