export interface GameTheme {
  name: string;
  items: {
    emoji: string;
    quiz: QuizQuestion;
  }[];
}

import React, { useState } from 'react';
import { GameTheme, TeamConfig } from '../types';
import { getThemeFromGemini } from '../services/geminiService';

interface SetupScreenProps {
  onComplete: (theme: GameTheme, teams: TeamConfig[]) => void;
  onLoading: () => void;
  currentTeams: TeamConfig[];
}

const COLOR_PRESETS: Record<string, Partial<TeamConfig>> = {
  blue: { bg: 'from-blue-500 to-indigo-600', border: 'border-blue-400', shadow: 'shadow-blue-500/40', text: 'text-blue-600', light: 'bg-blue-50' },
  rose: { bg: 'from-rose-500 to-red-600', border: 'border-rose-400', shadow: 'shadow-rose-500/40', text: 'text-rose-600', light: 'bg-rose-50' },
  amber: { bg: 'from-amber-400 to-orange-500', border: 'border-amber-400', shadow: 'shadow-amber-500/40', text: 'text-amber-600', light: 'bg-amber-50' },
  purple: { bg: 'from-fuchsia-500 to-purple-600', border: 'border-fuchsia-400', shadow: 'shadow-fuchsia-500/40', text: 'text-fuchsia-600', light: 'bg-fuchsia-50' },
  teal: { bg: 'from-teal-400 to-cyan-600', border: 'border-teal-400', shadow: 'shadow-teal-500/40', text: 'text-teal-600', light: 'bg-teal-50' },
  indigo: { bg: 'from-indigo-500 to-violet-700', border: 'border-indigo-400', shadow: 'shadow-indigo-500/40', text: 'text-indigo-600', light: 'bg-indigo-50' },
  emerald: { bg: 'from-emerald-500 to-green-700', border: 'border-emerald-400', shadow: 'shadow-emerald-500/40', text: 'text-emerald-600', light: 'bg-emerald-50' },
  orange: { bg: 'from-orange-500 to-red-600', border: 'border-orange-400', shadow: 'shadow-orange-500/40', text: 'text-orange-600', light: 'bg-orange-50' },
  pink: { bg: 'from-pink-500 to-rose-600', border: 'border-pink-400', shadow: 'shadow-pink-500/40', text: 'text-pink-600', light: 'bg-pink-50' },
  slate: { bg: 'from-slate-600 to-slate-800', border: 'border-slate-500', shadow: 'shadow-slate-500/40', text: 'text-slate-600', light: 'bg-slate-50' },
};

const ICONS = ['fa-dragon', 'fa-fire', 'fa-bolt', 'fa-star', 'fa-leaf', 'fa-ghost', 'fa-rocket', 'fa-shield-halved', 'fa-paw', 'fa-crown', 'fa-gem', 'fa-mask'];

export const SetupScreen: React.FC<SetupScreenProps> = ({ onComplete, onLoading, currentTeams }) => {
  const [mode, setMode] = useState<'CHOICE' | 'AI' | 'MANUAL' | 'TEAMS'>('CHOICE');
  const [prompt, setPrompt] = useState('');
  const [teams, setTeams] = useState<TeamConfig[]>(currentTeams);
  const [manualTheme, setManualTheme] = useState<GameTheme>({
    name: 'Chủ đề tùy chỉnh',
    items: Array(6).fill(null).map(() => ({
      emoji: '⭐',
      quiz: { question: '', options: ['', '', '', ''], correctAnswer: '' }
    }))
  });

  const handleAiSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;
    onLoading();
    const theme = await getThemeFromGemini(userPromptWithMathInstruction(prompt));
    onComplete(theme, teams);
  };

  const userPromptWithMathInstruction = (p: string) => 
    `${p}. Lưu ý: Nếu có công thức toán học, hãy sử dụng định dạng LaTeX (ví dụ: $x^2 + y^2 = r^2$) để hiển thị đẹp mắt.`;

  const handleManualItemChange = (idx: number, field: string, value: any) => {
    const newItems = [...manualTheme.items];
    if (field === 'emoji') newItems[idx].emoji = value;
    else if (field === 'question') newItems[idx].quiz.question = value;
    else if (field === 'correctAnswer') newItems[idx].quiz.correctAnswer = value;
    setManualTheme({ ...manualTheme, items: newItems });
  };

  const handleOptionChange = (itemIdx: number, optIdx: number, value: string) => {
    const newItems = [...manualTheme.items];
    newItems[itemIdx].quiz.options[optIdx] = value;
    setManualTheme({ ...manualTheme, items: newItems });
  };

  const updateTeam = (idx: number, updates: Partial<TeamConfig>) => {
    const newTeams = [...teams];
    newTeams[idx] = { ...newTeams[idx], ...updates };
    setTeams(newTeams);
  };

  const handleThemeChange = (idx: number, themeKey: string) => {
    const preset = COLOR_PRESETS[themeKey];
    updateTeam(idx, { theme: themeKey, ...preset });
  };

  const validateManual = () => {
    return manualTheme.items.every(item => 
      item.emoji && item.quiz.question && 
      item.quiz.options.every(o => o) && 
      item.quiz.options.includes(item.quiz.correctAnswer)
    );
  };

  if (mode === 'CHOICE') {
    return (
      <div className="max-w-5xl mx-auto py-12 px-4 text-center animate-in fade-in slide-in-from-bottom-8 duration-1000">
        <div className="inline-block p-4 bg-emerald-100 rounded-3xl mb-8 animate-float">
          <i className="fa-solid fa-gamepad text-5xl text-emerald-600"></i>
        </div>
        <h2 className="text-6xl font-black text-slate-900 mb-6 tracking-tight">Chuẩn Bị Cuộc Đua</h2>
        <p className="text-slate-500 text-xl mb-12 font-medium max-w-2xl mx-auto leading-relaxed">
          Chào mừng Giáo viên! Hãy thiết lập câu hỏi và tùy chỉnh các đội chơi để bắt đầu.
        </p>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-12">
          <button 
            onClick={() => setMode('AI')}
            className="group relative p-10 bg-white rounded-[3rem] border-4 border-emerald-100 hover:border-emerald-500 transition-all shadow-xl flex flex-col items-center gap-6 overflow-hidden"
          >
            <div className="w-20 h-20 bg-emerald-100 rounded-3xl flex items-center justify-center group-hover:scale-110 transition-transform">
              <i className="fa-solid fa-wand-magic-sparkles text-3xl text-emerald-600"></i>
            </div>
            <h3 className="text-2xl font-black text-slate-800">Tạo Bằng AI</h3>
          </button>

          <button 
            onClick={() => setMode('MANUAL')}
            className="group relative p-10 bg-white rounded-[3rem] border-4 border-indigo-100 hover:border-indigo-500 transition-all shadow-xl flex flex-col items-center gap-6 overflow-hidden"
          >
            <div className="w-20 h-20 bg-indigo-100 rounded-3xl flex items-center justify-center group-hover:scale-110 transition-transform">
              <i className="fa-solid fa-pen-nib text-3xl text-indigo-600"></i>
            </div>
            <h3 className="text-2xl font-black text-slate-800">Tự Soạn</h3>
          </button>

          <button 
            onClick={() => setMode('TEAMS')}
            className="group relative p-10 bg-white rounded-[3rem] border-4 border-rose-100 hover:border-rose-500 transition-all shadow-xl flex flex-col items-center gap-6 overflow-hidden"
          >
            <div className="w-20 h-20 bg-rose-100 rounded-3xl flex items-center justify-center group-hover:scale-110 transition-transform">
              <i className="fa-solid fa-users-gear text-3xl text-rose-600"></i>
            </div>
            <h3 className="text-2xl font-black text-slate-800">Tùy Chỉnh Đội</h3>
          </button>
        </div>
      </div>
    );
  }

  if (mode === 'TEAMS') {
    return (
      <div className="max-w-6xl mx-auto py-10 px-4 animate-in fade-in duration-700">
        <div className="flex items-center justify-between mb-12">
          <button onClick={() => setMode('CHOICE')} className="text-emerald-600 hover:text-emerald-800 font-black flex items-center gap-3 text-lg">
            <i className="fa-solid fa-circle-chevron-left"></i> Quay lại
          </button>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Tùy Chỉnh 5 Đội Chơi</h2>
          <div className="w-32"></div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-1 gap-6">
          {teams.map((team, idx) => (
            <div key={idx} className="bg-white p-8 rounded-[3rem] shadow-xl border-2 border-slate-50 flex flex-col md:flex-row items-center gap-8 group">
              <div className={`w-24 h-24 rounded-[2rem] bg-gradient-to-br ${team.bg} flex items-center justify-center text-white text-4xl shadow-lg shrink-0 group-hover:rotate-6 transition-all duration-500`}>
                <i className={`fa-solid ${team.icon}`}></i>
              </div>

              <div className="flex-grow space-y-4 w-full">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Tên Đội</label>
                    <input 
                      value={team.name}
                      onChange={e => updateTeam(idx, { name: e.target.value })}
                      className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700 focus:ring-2 focus:ring-emerald-500"
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Biểu Tượng</label>
                    <div className="flex flex-wrap gap-2">
                      {ICONS.map(icon => (
                        <button 
                          key={icon}
                          onClick={() => updateTeam(idx, { icon })}
                          className={`w-10 h-10 rounded-lg flex items-center justify-center transition-all ${team.icon === icon ? 'bg-emerald-600 text-white scale-110' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                        >
                          <i className={`fa-solid ${icon} text-sm`}></i>
                        </button>
                      ))}
                    </div>
                  </div>
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Màu Sắc Chủ Đạo</label>
                  <div className="flex flex-wrap gap-3">
                    {Object.keys(COLOR_PRESETS).map(key => (
                      <button 
                        key={key}
                        onClick={() => handleThemeChange(idx, key)}
                        className={`w-8 h-8 rounded-full border-4 transition-all ${team.theme === key ? 'border-emerald-500 scale-125' : 'border-transparent'} bg-gradient-to-br ${COLOR_PRESETS[key].bg}`}
                        title={key}
                      />
                    ))}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-12 text-center">
          <button 
            onClick={() => setMode('CHOICE')}
            className="px-16 py-5 bg-emerald-600 text-white rounded-[2rem] font-black text-xl shadow-xl hover:bg-emerald-700 transition-all active:scale-95"
          >
            LƯU CẤU HÌNH ĐỘI
          </button>
        </div>
      </div>
    );
  }

  if (mode === 'AI') {
    return (
      <div className="max-w-3xl mx-auto py-20 px-4 animate-in zoom-in duration-500">
        <button onClick={() => setMode('CHOICE')} className="mb-10 text-emerald-600 hover:text-emerald-800 font-black flex items-center gap-3 text-lg">
          <i className="fa-solid fa-circle-chevron-left"></i> Quay lại
        </button>
        <div className="glass-panel p-16 rounded-[4rem] shadow-2xl relative">
          <h3 className="text-4xl font-black text-slate-900 mb-8">Chủ Đề Mong Muốn?</h3>
          <form onSubmit={handleAiSubmit} className="space-y-10">
            <input 
              autoFocus
              value={prompt}
              onChange={e => setPrompt(e.target.value)}
              placeholder="Ví dụ: Lịch sử Việt Nam, Địa lý thế giới..."
              className="w-full bg-slate-100 border-none rounded-3xl px-8 py-6 text-xl font-bold focus:ring-4 focus:ring-emerald-500/10 outline-none"
            />
            <button className="w-full py-6 bg-emerald-600 text-white rounded-3xl font-black text-2xl shadow-lg hover:bg-emerald-700 transition-all">
              TẠO TRÒ CHƠI & CHƠI NGAY
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto py-10 px-4 animate-in fade-in duration-700">
      <div className="flex items-center justify-between mb-12">
        <button onClick={() => setMode('CHOICE')} className="text-slate-400 hover:text-emerald-600 font-bold flex items-center gap-2 text-lg">
          <i className="fa-solid fa-arrow-left"></i> Quay lại
        </button>
        <button 
          onClick={() => validateManual() && onComplete(manualTheme, teams)}
          disabled={!validateManual()}
          className="px-12 py-5 bg-emerald-600 text-white rounded-3xl font-black text-xl shadow-xl hover:bg-emerald-700 disabled:bg-slate-200 transition-all"
        >
          BẮT ĐẦU CHƠI
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {manualTheme.items.map((item, idx) => (
          <div key={idx} className="bg-white p-10 rounded-[3rem] shadow-xl border-4 border-slate-50 relative group">
            <div className="absolute top-6 right-10 text-slate-100 group-hover:text-emerald-50 font-black text-6xl">0{idx+1}</div>
            <div className="mb-6 relative z-10">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Emoji</label>
              <input 
                value={item.emoji}
                onChange={e => handleManualItemChange(idx, 'emoji', e.target.value)}
                className="w-16 h-16 text-3xl text-center bg-slate-50 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none"
              />
            </div>
            <div className="mb-6 relative z-10">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Câu hỏi</label>
              <textarea 
                value={item.quiz.question}
                onChange={e => handleManualItemChange(idx, 'question', e.target.value)}
                rows={2}
                className="w-full bg-slate-50 rounded-2xl px-5 py-4 text-sm font-bold focus:ring-2 focus:ring-emerald-500 outline-none"
              />
            </div>
            <div className="space-y-3 relative z-10">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Lựa chọn</label>
              {item.quiz.options.map((opt, oIdx) => (
                <div key={oIdx} className="flex gap-2 items-center">
                  <input 
                    type="radio"
                    name={`correct-${idx}`}
                    checked={item.quiz.correctAnswer === opt && opt !== ''}
                    onChange={() => handleManualItemChange(idx, 'correctAnswer', opt)}
                  />
                  <input 
                    value={opt}
                    onChange={e => handleOptionChange(idx, oIdx, e.target.value)}
                    className="flex-grow bg-slate-50 rounded-xl px-4 py-2 text-xs font-bold"
                  />
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { CardData, GameStatus, GameTheme, QuizQuestion, TeamConfig } from './types';
import { audioService } from './services/audioService';
import { Card } from './components/Card';
import { QuestionModal } from './components/QuestionModal';
import { SetupScreen } from './components/SetupScreen';

const DEFAULT_TEAMS: TeamConfig[] = [
  { name: 'Đội Rồng Xanh', theme: 'blue', icon: 'fa-dragon', bg: 'from-blue-500 to-indigo-600', border: 'border-blue-400', shadow: 'shadow-blue-500/40', text: 'text-blue-600', light: 'bg-blue-50' },
  { name: 'Đội Phượng Hoàng', theme: 'rose', icon: 'fa-fire', bg: 'from-rose-500 to-red-600', border: 'border-rose-400', shadow: 'shadow-rose-500/40', text: 'text-rose-600', light: 'bg-rose-50' },
  { name: 'Đội Sét Vàng', theme: 'amber', icon: 'fa-bolt', bg: 'from-amber-400 to-orange-500', border: 'border-amber-400', shadow: 'shadow-amber-500/40', text: 'text-amber-600', light: 'bg-amber-50' },
  { name: 'Đội Sao Tím', theme: 'purple', icon: 'fa-star', bg: 'from-fuchsia-500 to-purple-600', border: 'border-fuchsia-400', shadow: 'shadow-fuchsia-500/40', text: 'text-fuchsia-600', light: 'bg-fuchsia-50' },
  { name: 'Đội Lá Xanh', theme: 'teal', icon: 'fa-leaf', bg: 'from-teal-400 to-cyan-600', border: 'border-teal-400', shadow: 'shadow-teal-500/40', text: 'text-teal-600', light: 'bg-teal-50' },
];

const App: React.FC = () => {
  const [theme, setTheme] = useState<GameTheme | null>(null);
  const [teams, setTeams] = useState<TeamConfig[]>(DEFAULT_TEAMS);
  const [cards, setCards] = useState<CardData[]>([]);
  const [flippedIndices, setFlippedIndices] = useState<number[]>([]);
  const [status, setStatus] = useState<GameStatus>(GameStatus.SETUP);
  const [activeTeam, setActiveTeam] = useState(0);
  const [scores, setScores] = useState([0, 0, 0, 0, 0]);
  const [activeQuestion, setActiveQuestion] = useState<QuizQuestion | null>(null);

  const initializeGame = useCallback(async (gameTheme: GameTheme, customTeams?: TeamConfig[]) => {
    if (customTeams) setTeams(customTeams);

    const cardPairs: CardData[] = [];
    gameTheme.items.forEach((item, idx) => {
      const cardBase = { content: item.emoji, isFlipped: false, isMatched: false, question: item.quiz };
      cardPairs.push({ ...cardBase, id: idx * 2 });
      cardPairs.push({ ...cardBase, id: idx * 2 + 1 });
    });

    const shuffled = cardPairs.sort(() => Math.random() - 0.5);
    setCards(shuffled);
    setTheme(gameTheme);
    setScores([0, 0, 0, 0, 0]);
    setActiveTeam(0);
    setStatus(GameStatus.PLAYING);
    setFlippedIndices([]);
  }, []);

  const handleCardClick = (id: number) => {
    if (flippedIndices.length === 2 || status !== GameStatus.PLAYING) return;

    audioService.playFlip();
    const newFlipped = [...flippedIndices, id];
    setFlippedIndices(newFlipped);

    if (newFlipped.length === 2) {
      const card1 = cards.find(c => c.id === newFlipped[0]);
      const card2 = cards.find(c => c.id === newFlipped[1]);

      if (card1?.content === card2?.content) {
        setTimeout(() => {
          audioService.playMatch();
          setActiveQuestion(card1!.question || null);
          setStatus(GameStatus.QUESTION);
          setCards(prev => prev.map(c => 
            (c.id === card1!.id || c.id === card2!.id) ? { ...c, isMatched: true } : c
          ));
        }, 600);
      } else {
        setTimeout(() => {
          audioService.playWrong();
          setFlippedIndices([]);
          setActiveTeam(prev => (prev + 1) % teams.length);
        }, 1200);
      }
    }
  };

  const handleAnswer = (correct: boolean) => {
    if (correct) {
      audioService.playMatch();
      setScores(prev => {
        const next = [...prev];
        next[activeTeam] += 10;
        return next;
      });
    } else {
      audioService.playWrong();
      setActiveTeam(prev => (prev + 1) % teams.length);
    }

    setActiveQuestion(null);
    setStatus(GameStatus.PLAYING);
    setFlippedIndices([]);

    if (cards.every(c => c.isMatched)) {
      setStatus(GameStatus.WON);
      audioService.playVictory();
    }
  };

  const maxScore = Math.max(...scores);

  return (
    <div className="max-w-7xl mx-auto px-4 py-6 md:py-10 min-h-screen flex flex-col font-sans">
      <header className="flex flex-col md:flex-row items-center justify-between mb-10 gap-6">
        <div className="flex items-center gap-5">
          <div className="bg-gradient-to-br from-emerald-500 to-teal-700 p-4 rounded-3xl shadow-2xl animate-float">
            <i className="fa-solid fa-leaf text-white text-4xl"></i>
          </div>
          <div>
            <h1 className="text-4xl font-extrabold text-emerald-900 tracking-tight uppercase">TRÚC XANH</h1>
            <p className="text-slate-500 text-xs font-black uppercase tracking-widest mt-1">Multiplayer Memory Pro</p>
          </div>
        </div>

        {status !== GameStatus.SETUP && status !== GameStatus.LOADING && (
          <button 
            onClick={() => setStatus(GameStatus.SETUP)}
            className="px-8 py-4 bg-white text-emerald-600 rounded-[2rem] font-black shadow-lg hover:shadow-2xl transition-all border-2 border-emerald-50 group flex items-center gap-3"
          >
            <i className="fa-solid fa-gear group-hover:rotate-90 transition-transform duration-500"></i>
            TÙY CHỈNH MỚI
          </button>
        )}
      </header>

      {status === GameStatus.SETUP && (
        <SetupScreen 
          onComplete={initializeGame} 
          onLoading={() => setStatus(GameStatus.LOADING)} 
          currentTeams={teams}
        />
      )}

      {status === GameStatus.LOADING && (
        <div className="flex-grow flex flex-col items-center justify-center animate-pulse">
           <div className="w-24 h-24 border-8 border-emerald-100 border-t-emerald-600 rounded-full animate-spin mb-8"></div>
           <p className="text-3xl font-black text-emerald-900">Đang khởi tạo...</p>
        </div>
      )}

      {(status === GameStatus.PLAYING || status === GameStatus.QUESTION || status === GameStatus.WON) && (
        <main className="grid grid-cols-1 lg:grid-cols-12 gap-10 items-start flex-grow">
          <div className="lg:col-span-3 space-y-4">
            <div className="space-y-3">
              {teams.map((team, idx) => {
                const isActive = activeTeam === idx;
                return (
                  <div key={idx} className={`p-5 rounded-3xl transition-all duration-500 border-2 overflow-hidden relative ${
                    isActive 
                    ? `bg-gradient-to-r ${team.bg} ${team.border} shadow-2xl ${team.shadow} scale-105 z-10` 
                    : 'bg-white border-slate-100/50 opacity-60'
                  }`}>
                    <div className="flex items-center justify-between relative z-10">
                      <div className="flex items-center gap-3">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${isActive ? 'bg-white/20' : `${team.light} ${team.text}`}`}>
                          <i className={`fa-solid ${team.icon} text-lg`}></i>
                        </div>
                        <div>
                          <h3 className={`font-black text-xs tracking-tight ${isActive ? 'text-white' : 'text-slate-800'}`}>{team.name}</h3>
                        </div>
                      </div>
                      <p className={`text-2xl font-black ${isActive ? 'text-white' : team.text}`}>{scores[idx]}</p>
                    </div>
                  </div>
                );
              })}
            </div>
            <div className="glass-panel p-6 rounded-[2rem] shadow-xl border-2 border-emerald-50">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Chủ đề</label>
               <p className="text-lg font-black text-emerald-900 uppercase tracking-tight">{theme?.name}</p>
            </div>
          </div>

          <div className="lg:col-span-9">
            <div className="grid grid-cols-3 md:grid-cols-4 gap-6 p-8 glass-panel rounded-[3rem] shadow-2xl border-2 border-emerald-50">
              {cards.map((card, idx) => (
                <Card 
                  key={card.id} 
                  card={{...card, isFlipped: flippedIndices.includes(card.id)}} 
                  index={idx}
                  onClick={handleCardClick}
                  disabled={status !== GameStatus.PLAYING}
                />
              ))}
            </div>
          </div>
        </main>
      )}

      {activeQuestion && <QuestionModal question={activeQuestion} onAnswer={handleAnswer} />}

      {status === GameStatus.WON && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[150] flex items-center justify-center p-6">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full text-center shadow-2xl relative overflow-hidden">
            <div className="relative z-10">
