import { GoogleGenAI, Type } from "@google/genai";
import { GameTheme } from "../types";

export const getThemeFromGemini = async (userPrompt: string, pairCount: number = 6): Promise<GameTheme> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate exactly ${pairCount} unique items for a Vietnamese memory match game "Trúc Xanh" based on: "${userPrompt}". 
    For each item, provide an emoji and a simple trivia question related to it with 4 options and 1 correct answer.
    Return the theme name and the items list.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          items: { 
            type: Type.ARRAY, 
            items: { 
              type: Type.OBJECT,
              properties: {
                emoji: { type: Type.STRING },
                quiz: {
                  type: Type.OBJECT,
                  properties: {
                    question: { type: Type.STRING },
                    options: { type: Type.ARRAY, items: { type: Type.STRING } },
                    correctAnswer: { type: Type.STRING }
                  },
                  required: ["question", "options", "correctAnswer"]
                }
              },
              required: ["emoji", "quiz"]
            }
          }
        },
        required: ["name", "items"]
      }
    }
  });

  try {
    const data = JSON.parse(response.text || '{}');
    if (data.items && data.items.length >= pairCount) {
      return {
        name: data.name,
        items: data.items.slice(0, pairCount)
      };
    }
    throw new Error("Invalid data");
  } catch (error) {
    console.error("Gemini Error", error);
    // Fallback default items based on pairCount
    const defaultItems = [
      { emoji: "🍎", quiz: { question: "Táo có màu gì phổ biến nhất?", options: ["Xanh", "Đỏ", "Tím", "Vàng"], correctAnswer: "Đỏ" } },
      { emoji: "🍌", quiz: { question: "Chuối cung cấp nhiều chất gì?", options: ["Sắt", "Kali", "Canxi", "Kẽm"], correctAnswer: "Kali" } },
      { emoji: "🍇", quiz: { question: "Nho khô được làm từ gì?", options: ["Táo", "Nho tươi", "Mận", "Đào"], correctAnswer: "Nho tươi" } },
      { emoji: "🍓", quiz: { question: "Dâu tây thường trồng ở đâu tại VN?", options: ["Cần Thơ", "Đà Lạt", "Hà Nội", "Huế"], correctAnswer: "Đà Lạt" } },
      { emoji: "🍍", quiz: { question: "Quả dứa còn gọi là quả gì?", options: ["Mận", "Thơm", "Ổi", "Xoài"], correctAnswer: "Thơm" } },
      { emoji: "🍉", quiz: { question: "Dưa hấu có ruột màu gì?", options: ["Xanh", "Đỏ", "Trắng", "Đen"], correctAnswer: "Đỏ" } },
      { emoji: "🥑", quiz: { question: "Quả bơ có nhiều chất béo gì?", options: ["Bão hòa", "Không bão hòa", "Trans", "Xấu"], correctAnswer: "Không bão hòa" } },
      { emoji: "🥥", quiz: { question: "Nước cốt dừa làm từ đâu?", options: ["Nước dừa", "Cùi dừa", "Vỏ dừa", "Lá dừa"], correctAnswer: "Cùi dừa" } },
      { emoji: "🍋", quiz: { question: "Chanh có chứa nhiều vitamin nào?", options: ["A", "B", "C", "D"], correctAnswer: "C" } },
      { emoji: "🍒", quiz: { question: "Quả cherry thường có vị gì?", options: ["Chua ngọt", "Đắng", "Mặn", "Cay"], correctAnswer: "Chua ngọt" } }
    ];
    return {
      name: "Trái Cây",
      items: defaultItems.slice(0, pairCount)
    };
  }
};

import React, { useState, useEffect } from 'react';
import { GameTheme, TeamConfig } from '../types';
import { getThemeFromGemini } from '../services/geminiService';

interface SetupScreenProps {
  onComplete: (theme: GameTheme, teams: TeamConfig[]) => void;
  onLoading: () => void;
  currentTeams: TeamConfig[];
}

const COLOR_PRESETS: Record<string, Partial<TeamConfig>> = {
