              <i className="fa-solid fa-users-gear text-3xl text-rose-600"></i>
            </div>
            <h3 className="text-2xl font-black text-slate-800">Tùy Chỉnh Đội</h3>
          </button>
        </div>
      </div>
    );
  }

  if (mode === 'TEAMS') {
    return (
      <div className="max-w-6xl mx-auto py-10 px-4 animate-in fade-in duration-700">
        <div className="flex items-center justify-between mb-12">
          <button onClick={() => setMode('CHOICE')} className="text-emerald-600 hover:text-emerald-800 font-black flex items-center gap-3 text-lg">
            <i className="fa-solid fa-circle-chevron-left"></i> Quay lại
          </button>
          <h2 className="text-4xl font-black text-slate-900 tracking-tight">Tùy Chỉnh {teams.length} Đội Chơi</h2>
          <div className="w-32"></div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-1 gap-6">
          {teams.map((team, idx) => (
            <div key={idx} className="bg-white p-8 rounded-[3rem] shadow-xl border-2 border-slate-50 flex flex-col md:flex-row items-center gap-8 group">
              <div className={`w-24 h-24 rounded-[2rem] bg-gradient-to-br ${team.bg} flex items-center justify-center text-white text-4xl shadow-lg shrink-0 group-hover:rotate-6 transition-all duration-500`}>
                <i className={`fa-solid ${team.icon}`}></i>
              </div>

              <div className="flex-grow space-y-4 w-full">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Tên Đội</label>
                    <input 
                      value={team.name}
                      onChange={e => updateTeam(idx, { name: e.target.value })}
                      className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold text-slate-700 focus:ring-2 focus:ring-emerald-500"
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Biểu Tượng</label>
