                          className={`w-10 h-10 rounded-lg flex items-center justify-center transition-all ${team.icon === icon ? 'bg-emerald-600 text-white scale-110' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                        >
                          <i className={`fa-solid ${icon} text-sm`}></i>
                        </button>
                      ))}
                    </div>
                  </div>
                </div>

                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Màu Sắc Chủ Đạo</label>
                  <div className="flex flex-wrap gap-3">
                    {Object.keys(COLOR_PRESETS).map(key => (
                      <button 
                        key={key}
                        onClick={() => handleThemeChange(idx, key)}
                        className={`w-8 h-8 rounded-full border-4 transition-all ${team.theme === key ? 'border-emerald-500 scale-125' : 'border-transparent'} bg-gradient-to-br ${COLOR_PRESETS[key].bg}`}
                        title={key}
                      />
                    ))}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-12 text-center">
          <button 
            onClick={() => setMode('CHOICE')}
            className="px-16 py-5 bg-emerald-600 text-white rounded-[2rem] font-black text-xl shadow-xl hover:bg-emerald-700 transition-all active:scale-95"
          >
            LƯU CẤU HÌNH ĐỘI
          </button>
        </div>
      </div>
    );
  }

  if (mode === 'AI') {
    return (
      <div className="max-w-3xl mx-auto py-20 px-4 animate-in zoom-in duration-500">
        <button onClick={() => setMode('CHOICE')} className="mb-10 text-emerald-600 hover:text-emerald-800 font-black flex items-center gap-3 text-lg">
          <i className="fa-solid fa-circle-chevron-left"></i> Quay lại
        </button>
        <div className="glass-panel p-16 rounded-[4rem] shadow-2xl relative">
          <h3 className="text-4xl font-black text-slate-900 mb-2">Chủ Đề Mong Muốn?</h3>
          <p className="text-slate-400 font-bold mb-8">AI sẽ tạo {pairCount} cặp thẻ dựa trên yêu cầu này cho {teams.length} đội chơi.</p>
          <form onSubmit={handleAiSubmit} className="space-y-10">
            <input 
              autoFocus
              value={prompt}
              onChange={e => setPrompt(e.target.value)}
              placeholder="Ví dụ: Lịch sử Việt Nam, Địa lý thế giới..."
              className="w-full bg-slate-100 border-none rounded-3xl px-8 py-6 text-xl font-bold focus:ring-4 focus:ring-emerald-500/10 outline-none"
            />
            <button className="w-full py-6 bg-emerald-600 text-white rounded-3xl font-black text-2xl shadow-lg hover:bg-emerald-700 transition-all">
              TẠO TRÒ CHƠI & CHƠI NGAY
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto py-10 px-4 animate-in fade-in duration-700">
      <div className="flex items-center justify-between mb-12">
        <button onClick={() => setMode('CHOICE')} className="text-slate-400 hover:text-emerald-600 font-bold flex items-center gap-2 text-lg">
          <i className="fa-solid fa-arrow-left"></i> Quay lại
        </button>
        <div className="text-center">
            <h3 className="text-2xl font-black text-slate-800">Soạn thảo {pairCount} cặp câu hỏi</h3>
            <p className="text-slate-400 text-sm font-bold uppercase tracking-widest mt-1">{teams.length} đội tham gia</p>
        </div>
        <button 
          onClick={() => validateManual() && onComplete(manualTheme, teams)}
