            <div className="absolute top-6 right-10 text-slate-100 group-hover:text-emerald-50 font-black text-6xl">0{idx+1}</div>
            <div className="mb-6 relative z-10">
              <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-3 block">Emoji</label>
              <input 
                value={item.emoji}
