import React, { useEffect, useState } from 'react';
import { QuizQuestion } from '../types';

interface QuestionModalProps {
  question: QuizQuestion;
  onAnswer: (correct: boolean) => void;
}

const TIMER_DURATION = 45;

export const QuestionModal: React.FC<QuestionModalProps> = ({ question, onAnswer }) => {
  const [timeLeft, setTimeLeft] = useState(TIMER_DURATION);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showResult, setShowResult] = useState(false);

  // Trigger MathJax typesetting when the modal content changes or result shows
  useEffect(() => {
    if ((window as any).MathJax) {
      (window as any).MathJax.typesetPromise().catch((err: Error) => console.error('MathJax error:', err));
    }
  }, [question, showResult]);

  // Countdown timer logic
  useEffect(() => {
    if (showResult) return; // Stop timer when answer is selected

    if (timeLeft <= 0) {
      handleOptionClick(null); // Time out
      return;
    }

    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);

    return () => clearInterval(timer);
  }, [timeLeft, showResult]);

  const handleOptionClick = (opt: string | null) => {
    if (showResult) return;
    setSelectedOption(opt);
    setShowResult(true);
  };

  const handleContinue = () => {
    onAnswer(selectedOption === question.correctAnswer);
  };

  const timerColor = timeLeft > 10 ? 'text-emerald-500' : 'text-rose-500 animate-pulse';
  const progressWidth = (timeLeft / TIMER_DURATION) * 100;

  return (
    <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[100] flex items-center justify-center p-4 sm:p-6">
      <div className="bg-white rounded-[3rem] w-full max-w-3xl shadow-[0_32px_64px_-16px_rgba(0,0,0,0.4)] overflow-hidden animate-in fade-in zoom-in duration-300">

        {/* Header with Timer */}
        <div className="bg-gradient-to-r from-emerald-600 to-teal-600 px-8 py-6 text-white flex items-center justify-between relative overflow-hidden">
          <div className="flex items-center gap-4 z-10">
            <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center shrink-0 backdrop-blur-sm">
              <i className="fa-solid fa-brain text-2xl text-yellow-300"></i>
            </div>
            <div>
              <h3 className="text-2xl font-black tracking-tight">Thử Thách Trí Tuệ</h3>
              <p className="text-emerald-100 text-xs font-bold uppercase tracking-widest">
                {showResult ? 'Kết quả câu hỏi' : 'Chọn đáp án đúng nhất'}
              </p>
            </div>
          </div>

          {!showResult && (
            <div className="flex flex-col items-end z-10">
              <div className={`text-5xl font-black tabular-nums ${timerColor}`}>
                {timeLeft}s
              </div>
            </div>
          )}

          <div className="absolute -right-4 -bottom-4 w-32 h-32 bg-white/5 rounded-full blur-3xl"></div>

          {/* Progress Bar Background */}
          {!showResult && (
            <div className="absolute bottom-0 left-0 w-full h-2 bg-white/10">
               <div 
                 className={`h-full transition-all duration-1000 ease-linear ${timeLeft > 15 ? 'bg-emerald-400' : 'bg-rose-400'}`} 
                 style={{ width: `${progressWidth}%` }}
               ></div>
            </div>
          )}
        </div>

        <div className="p-8 sm:p-12">
          {/* Question text */}
          <div className="mb-10 text-center">
            <p className="text-3xl font-extrabold text-slate-800 leading-tight">
              {question.question}
            </p>
          </div>

          {/* Result View or Option Selection */}
          {showResult ? (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className={`p-8 rounded-[2rem] mb-8 text-center border-4 ${selectedOption === question.correctAnswer ? 'bg-emerald-50 border-emerald-500' : 'bg-rose-50 border-rose-500'}`}>
                <div className={`w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 ${selectedOption === question.correctAnswer ? 'bg-emerald-500 text-white' : 'bg-rose-500 text-white'}`}>
                  <i className={`fa-solid ${selectedOption === question.correctAnswer ? 'fa-check' : 'fa-xmark'} text-4xl`}></i>
                </div>
                <h4 className={`text-2xl font-black mb-2 ${selectedOption === question.correctAnswer ? 'text-emerald-700' : 'text-rose-700'}`}>
                  {selectedOption === question.correctAnswer ? 'Chính Xác!' : (selectedOption === null ? 'Hết giờ rồi!' : 'Rất tiếc, chưa đúng!')}
                </h4>
                <p className="text-slate-600 font-bold text-lg mb-4">
                  Đáp án đúng là: <span className="text-emerald-600">{question.correctAnswer}</span>
                </p>
                <div className="pt-6 border-t border-slate-200">
                  <p className="text-sm font-black text-slate-400 uppercase tracking-widest mb-2">Giải thích</p>
                  <p className="text-slate-700 font-medium leading-relaxed italic">
                    {question.explanation || "Không có giải thích cho câu hỏi này."}
                  </p>
                </div>
              </div>

              <button
                onClick={handleContinue}
                className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black text-2xl shadow-xl hover:bg-emerald-600 transition-all active:scale-95 flex items-center justify-center gap-4"
              >
                TIẾP TỤC TRÒ CHƠI <i className="fa-solid fa-arrow-right"></i>
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 gap-5">
              {question.options.map((opt, idx) => (
                <button
                  key={idx}
                  onClick={() => handleOptionClick(opt)}
                  className="w-full p-6 text-left rounded-[2rem] border-4 border-slate-100 hover:border-emerald-500 hover:bg-emerald-50 transition-all font-black text-slate-800 flex items-center gap-6 group active:scale-[0.98] shadow-sm hover:shadow-md"
                >
                  <span className="w-14 h-14 rounded-2xl bg-slate-100 flex items-center justify-center text-2xl text-slate-500 font-black group-hover:bg-emerald-600 group-hover:text-white transition-colors shrink-0">
                    {String.fromCharCode(65 + idx)}
                  </span>
                  <span className="flex-grow text-xl md:text-2xl leading-snug">{opt}</span>
                </button>
              ))}
            </div>
          )}

          {!showResult && (
            <div className="mt-10 text-center">
              <div className="inline-flex items-center gap-3 px-6 py-3 bg-slate-50 rounded-full border border-slate-100">
                 <span className={`w-3 h-3 rounded-full animate-pulse ${timeLeft > 15 ? 'bg-emerald-500' : 'bg-rose-500'}`}></span>
                 <p className="text-xs font-black text-slate-400 uppercase tracking-widest">
                   Nhanh lên, bạn còn {timeLeft} giây!
                 </p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

