      <div className="bg-white rounded-[3rem] w-full max-w-3xl shadow-[0_32px_64px_-16px_rgba(0,0,0,0.4)] overflow-hidden animate-in fade-in zoom-in duration-300">

        {/* Header with Timer */}
        <div className="bg-gradient-to-r from-emerald-600 to-teal-600 px-8 py-6 text-white flex items-center justify-between relative overflow-hidden">
          <div className="flex items-center gap-4 z-10">
            <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center shrink-0 backdrop-blur-sm">
              <i className="fa-solid fa-brain text-2xl text-yellow-300"></i>
            </div>
            <div>
              <h3 className="text-2xl font-black tracking-tight uppercase">Thử Thách</h3>
              <p className="text-emerald-100 text-[10px] font-bold uppercase tracking-widest">
                {showResult ? 'Kết quả câu hỏi' : 'Chọn đáp án đúng nhất'}
              </p>
            </div>
          </div>

          {!showResult && (
            <div className="flex flex-col items-end z-10">
              <div className={`text-4xl font-black tabular-nums ${timerColor}`}>
                {timeLeft}s
              </div>
            </div>
          )}

          <div className="absolute -right-4 -bottom-4 w-32 h-32 bg-white/5 rounded-full blur-3xl"></div>

          {/* Progress Bar Background */}
          {!showResult && (
            <div className="absolute bottom-0 left-0 w-full h-2 bg-white/10">
               <div 
                 className={`h-full transition-all duration-1000 ease-linear ${timeLeft > 15 ? 'bg-emerald-400' : 'bg-rose-400'}`} 
                 style={{ width: `${progressWidth}%` }}
               ></div>
            </div>
          )}
        </div>

        <div className="p-8 sm:p-10">
          {/* Question text */}
          <div className="mb-8 text-center px-4">
            <p className="text-2xl sm:text-3xl font-extrabold text-slate-800 leading-tight">
              {question.question}
            </p>
          </div>

          {/* Result View or Option Selection */}
          {showResult ? (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className={`p-6 sm:p-8 rounded-[2.5rem] mb-6 text-center border-4 ${selectedOption === question.correctAnswer ? 'bg-emerald-50 border-emerald-500' : 'bg-rose-50 border-rose-500'}`}>
                <div className={`w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 ${selectedOption === question.correctAnswer ? 'bg-emerald-500 text-white' : 'bg-rose-500 text-white'}`}>
                  <i className={`fa-solid ${selectedOption === question.correctAnswer ? 'fa-check' : 'fa-xmark'} text-3xl`}></i>
                </div>
                <h4 className={`text-xl font-black mb-1 ${selectedOption === question.correctAnswer ? 'text-emerald-700' : 'text-rose-700'}`}>
                  {selectedOption === question.correctAnswer ? 'CHÍNH XÁC!' : (selectedOption === null ? 'HẾT GIỜ RỒI!' : 'CHƯA ĐÚNG!')}
                </h4>
                <p className="text-slate-600 font-bold text-base mb-4">
                  Đáp án: <span className="text-emerald-600">{question.correctAnswer}</span>
                </p>
                <div className="pt-4 border-t border-slate-200">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Giải thích chi tiết</p>
                  <p className="text-slate-700 font-semibold leading-relaxed text-sm sm:text-base">
                    {question.explanation || "Không có giải thích chi tiết cho câu hỏi này."}
                  </p>
                </div>
              </div>

              <button
                onClick={handleContinue}
                className="w-full py-5 bg-emerald-600 text-white rounded-[2rem] font-black text-xl shadow-xl hover:bg-emerald-700 transition-all active:scale-95 flex items-center justify-center gap-3"
              >
                TIẾP TỤC <i className="fa-solid fa-arrow-right"></i>
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {question.options.map((opt, idx) => (
                <button
                  key={idx}
                  onClick={() => handleOptionClick(opt)}
                  className="w-full p-4 sm:p-5 text-left rounded-[1.5rem] border-2 border-slate-100 hover:border-emerald-500 hover:bg-emerald-50 transition-all font-bold text-slate-800 flex items-center gap-4 group active:scale-[0.98] shadow-sm hover:shadow-md"
                >
                  <span className="w-12 h-12 rounded-xl bg-slate-50 flex items-center justify-center text-xl text-slate-400 font-black group-hover:bg-emerald-600 group-hover:text-white transition-colors shrink-0">
                    {String.fromCharCode(65 + idx)}
                  </span>
                  <span className="flex-grow text-lg sm:text-xl leading-snug truncate-2-lines">{opt}</span>
                </button>
              ))}
            </div>
          )}

          {!showResult && (
            <div className="mt-8 text-center">
              <div className="inline-flex items-center gap-3 px-5 py-2 bg-slate-50 rounded-full border border-slate-100">
                 <span className={`w-2 h-2 rounded-full animate-pulse ${timeLeft > 15 ? 'bg-emerald-500' : 'bg-rose-500'}`}></span>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                   Thời gian còn lại: {timeLeft} giây
                 </p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

class AudioService {
  private ctx: AudioContext | null = null;

  private init() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  }

  private playTone(freq: number, type: OscillatorType, duration: number, volume: number = 0.1, startTime: number = 0) {
    this.init();
    if (!this.ctx) return;
    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.type = type;
    osc.frequency.setValueAtTime(freq, this.ctx.currentTime + startTime);

    gain.gain.setValueAtTime(volume, this.ctx.currentTime + startTime);
    gain.gain.exponentialRampToValueAtTime(0.0001, this.ctx.currentTime + startTime + duration);

    osc.connect(gain);
    gain.connect(this.ctx.destination);

    osc.start(this.ctx.currentTime + startTime);
    osc.stop(this.ctx.currentTime + startTime + duration);
  }

  private playNoise(duration: number, volume: number = 0.1, startTime: number = 0) {
    this.init();
    if (!this.ctx) return;

    const bufferSize = this.ctx.sampleRate * duration;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);

    for (let i = 0; i < bufferSize; i++) {
      data[i] = Math.random() * 2 - 1;
    }

    const noise = this.ctx.createBufferSource();
    noise.buffer = buffer;

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(volume, this.ctx.currentTime + startTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.ctx.currentTime + startTime + duration);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = 1000;

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.ctx.destination);

    noise.start(this.ctx.currentTime + startTime);
  }

  playFlip() {
    this.playTone(400, 'sine', 0.1, 0.05);
  }

  playMatch() {
    // Âm thanh khi ghép đúng 2 thẻ
    this.playTone(523.25, 'sine', 0.4, 0.1); 
    this.playTone(659.25, 'sine', 0.4, 0.1, 0.1);
  }

  playCorrectAnswer() {
    // Hiệu ứng vỗ tay (clapping) kết hợp tiếng chuông thành công
    // Tiếng chuông
    this.playTone(523.25, 'triangle', 0.5, 0.1);
    this.playTone(659.25, 'triangle', 0.5, 0.1, 0.1);
    this.playTone(783.99, 'triangle', 0.5, 0.1, 0.2);
    this.playTone(1046.50, 'triangle', 0.8, 0.1, 0.3);

    // Giả lập tiếng vỗ tay bằng các chuỗi noise ngắn
    for (let i = 0; i < 12; i++) {
      const start = 0.1 + (i * 0.08) + (Math.random() * 0.03);
      this.playNoise(0.1, 0.05, start);
    }
  }

  playWrongAnswer() {
    // Âm thanh báo lỗi trầm và rè (dissonant)
    this.playTone(150, 'sawtooth', 0.4, 0.1);
    this.playTone(110, 'sawtooth', 0.6, 0.1, 0.1);
  }

  playWrong() {
    // Âm thanh khi lật 2 thẻ không giống nhau
    this.playTone(200, 'sawtooth', 0.3, 0.05);
    this.playTone(150, 'sawtooth', 0.3, 0.05, 0.15);
  }

  playVictory() {
    // Nhạc chiến thắng rộn ràng (C Major Arpeggio)
    const melody = [523, 659, 783, 1046, 783, 659, 1046, 1318];
    melody.forEach((freq, i) => {
      this.playTone(freq, 'square', 0.4, 0.03, i * 0.15);
    });

    // Vỗ tay chúc mừng
    for (let i = 0; i < 20; i++) {
      this.playNoise(0.15, 0.04, 0.5 + (i * 0.1));
    }
  }
}

export const audioService = new AudioService();

import React, { useState, useCallback } from 'react';
import { CardData, GameStatus, GameTheme, QuizQuestion, TeamConfig } from './types';
import { audioService } from './services/audioService';
import { Card } from './components/Card';
import { QuestionModal } from './components/QuestionModal';
import { SetupScreen } from './components/SetupScreen';

const DEFAULT_TEAMS: TeamConfig[] = [
  { name: 'Đội Rồng Xanh', theme: 'blue', icon: 'fa-dragon', bg: 'from-blue-500 to-indigo-600', border: 'border-blue-400', shadow: 'shadow-blue-500/40', text: 'text-blue-600', light: 'bg-blue-50' },
  { name: 'Đội Phượng Hoàng', theme: 'rose', icon: 'fa-fire', bg: 'from-rose-500 to-red-600', border: 'border-rose-400', shadow: 'shadow-rose-500/40', text: 'text-rose-600', light: 'bg-rose-50' },
  { name: 'Đội Sét Vàng', theme: 'amber', icon: 'fa-bolt', bg: 'from-amber-400 to-orange-500', border: 'border-amber-400', shadow: 'shadow-amber-500/40', text: 'text-amber-600', light: 'bg-amber-50' },
  { name: 'Đội Sao Tím', theme: 'purple', icon: 'fa-star', bg: 'from-fuchsia-500 to-purple-600', border: 'border-fuchsia-400', shadow: 'shadow-fuchsia-500/40', text: 'text-fuchsia-600', light: 'bg-fuchsia-50' },
  { name: 'Đội Lá Xanh', theme: 'teal', icon: 'fa-leaf', bg: 'from-teal-400 to-cyan-600', border: 'border-teal-400', shadow: 'shadow-teal-500/40', text: 'text-teal-600', light: 'bg-teal-50' },
];

const App: React.FC = () => {
  const [theme, setTheme] = useState<GameTheme | null>(null);
  const [teams, setTeams] = useState<TeamConfig[]>(DEFAULT_TEAMS);
  const [cards, setCards] = useState<CardData[]>([]);
  const [flippedIndices, setFlippedIndices] = useState<number[]>([]);
  const [status, setStatus] = useState<GameStatus>(GameStatus.SETUP);
  const [activeTeam, setActiveTeam] = useState(0);
  const [scores, setScores] = useState<number[]>([]);
  const [activeQuestion, setActiveQuestion] = useState<QuizQuestion | null>(null);
  const [lastMatchedPair, setLastMatchedPair] = useState<number[]>([]);

  const shuffleArray = <T,>(array: T[]): T[] => {
    const newArr = [...array];
    for (let i = newArr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [newArr[i], newArr[j]] = [newArr[j], newArr[i]];
    }
    return newArr;
  };

  const initializeGame = useCallback(async (gameTheme: GameTheme, customTeams?: TeamConfig[]) => {
    const finalTeams = customTeams || DEFAULT_TEAMS;
    setTeams(finalTeams);

    const cardPairs: CardData[] = [];
    gameTheme.items.forEach((item, idx) => {
      const cardBase = { content: item.emoji, isFlipped: false, isMatched: false, question: item.quiz };
      cardPairs.push({ ...cardBase, id: idx * 2 });
      cardPairs.push({ ...cardBase, id: idx * 2 + 1 });
    });

    setCards(shuffleArray(cardPairs));
    setTheme(gameTheme);
    setScores(new Array(finalTeams.length).fill(0));
    setActiveTeam(0);
    setStatus(GameStatus.PLAYING);
    setFlippedIndices([]);
    setLastMatchedPair([]);
  }, []);

  const handleCardClick = (id: number) => {
    if (flippedIndices.length === 2 || status !== GameStatus.PLAYING) return;

    audioService.init(); // Đảm bảo AudioContext được khởi tạo từ tương tác người dùng
    audioService.playFlip();
    const newFlipped = [...flippedIndices, id];
    setFlippedIndices(newFlipped);

    if (newFlipped.length === 2) {
      const card1 = cards.find(c => c.id === newFlipped[0]);
      const card2 = cards.find(c => c.id === newFlipped[1]);

      if (card1?.content === card2?.content) {
        setLastMatchedPair(newFlipped);
        setTimeout(() => {
          audioService.playMatch();
          setActiveQuestion(card1!.question || null);
          setStatus(GameStatus.QUESTION);
          setCards(prev => prev.map(c => 
            (c.id === card1!.id || c.id === card2!.id) ? { ...c, isMatched: true } : c
          ));
        }, 600);
      } else {
        setTimeout(() => {
          audioService.playWrong();
          setFlippedIndices([]);
          setActiveTeam(prev => (prev + 1) % teams.length);
        }, 1200);
      }
    }
  };

  const handleAnswer = (correct: boolean) => {
    const nextTeamIndex = (activeTeam + 1) % teams.length;

    if (correct) {
      audioService.playCorrectAnswer(); // Tiếng vỗ tay và chuông thành công
      setScores(prev => {
        const next = [...prev];
        next[activeTeam] += 10;
        return next;
      });

      setActiveQuestion(null);
      setStatus(GameStatus.PLAYING);
      setFlippedIndices([]);
      setLastMatchedPair([]);
      // KHÔNG đổi đội chơi nếu trả lời đúng - Đội hiện tại được đi tiếp

      if (cards.every(c => c.isMatched)) {
        setStatus(GameStatus.WON);
        audioService.playVictory(); // Nhạc chiến thắng
      }
    } else {
      audioService.playWrongAnswer(); // Tiếng báo lỗi trầm rè
      setCards(prev => {
        const resetCards = prev.map(c => 
          lastMatchedPair.includes(c.id) ? { ...c, isMatched: false, isFlipped: false } : c
        );
        return shuffleArray(resetCards);
      });

      setActiveQuestion(null);
      setStatus(GameStatus.PLAYING);
      setFlippedIndices([]);
      setLastMatchedPair([]);
      // Đổi sang đội tiếp theo nếu trả lời sai
      setActiveTeam(nextTeamIndex);
    }
  };

  const maxScore = Math.max(...scores);

  const getGridCols = () => {
    const count = cards.length;
    if (count <= 12) return 'grid-cols-3 md:grid-cols-4';
    if (count <= 16) return 'grid-cols-4';
    if (count <= 20) return 'grid-cols-4 md:grid-cols-5';
    return 'grid-cols-4 md:grid-cols-6';
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-6 md:py-10 min-h-screen flex flex-col font-sans text-slate-800">
      <header className="flex flex-col md:flex-row items-center justify-between mb-10 gap-6">
        <div className="flex items-center gap-5">
          <div className="bg-gradient-to-br from-emerald-500 to-teal-700 p-4 rounded-3xl shadow-2xl animate-float">
            <i className="fa-solid fa-leaf text-white text-4xl"></i>
          </div>
          <div>
            <h1 className="text-4xl font-extrabold text-emerald-900 tracking-tight uppercase">TRÚC XANH</h1>
            <p className="text-slate-500 text-xs font-black uppercase tracking-widest mt-1">Memory Match Tournament</p>
          </div>
        </div>

        {status !== GameStatus.SETUP && (
          <button 
            onClick={() => setStatus(GameStatus.SETUP)}
            className="px-8 py-4 bg-white text-emerald-600 rounded-[2rem] font-black shadow-lg hover:shadow-2xl transition-all border-2 border-emerald-50 group flex items-center gap-3"
          >
            <i className="fa-solid fa-gear group-hover:rotate-90 transition-transform duration-500"></i>
            TÙY CHỈNH MỚI
          </button>
        )}
      </header>

      {status === GameStatus.SETUP && (
        <SetupScreen 
          onComplete={initializeGame} 
          onLoading={() => {}} 
          currentTeams={teams}
        />
      )}

      {(status === GameStatus.PLAYING || status === GameStatus.QUESTION || status === GameStatus.WON) && (
        <main className="grid grid-cols-1 lg:grid-cols-12 gap-10 items-start flex-grow">
          <div className="lg:col-span-3 space-y-4">
            <div className="space-y-3">
              {teams.map((team, idx) => {
                const isActive = activeTeam === idx;
                return (
                  <div key={idx} className={`p-5 rounded-3xl transition-all duration-500 border-2 overflow-hidden relative ${
                    isActive 
                    ? `bg-gradient-to-r ${team.bg} ${team.border} shadow-2xl ${team.shadow} scale-105 z-10` 
                    : 'bg-white border-slate-100/50 opacity-60'
                  }`}>
                    <div className="flex items-center justify-between relative z-10">
                      <div className="flex items-center gap-3">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${isActive ? 'bg-white/20' : `${team.light} ${team.text}`}`}>
                          <i className={`fa-solid ${team.icon} text-lg`}></i>
                        </div>
                        <div>
                          <h3 className={`font-black text-xs tracking-tight ${isActive ? 'text-white' : 'text-slate-800'}`}>{team.name}</h3>
                          {isActive && <span className="text-[9px] font-bold text-white/80 uppercase tracking-widest">Đang cầm lượt</span>}
                        </div>
                      </div>
                      <p className={`text-2xl font-black ${isActive ? 'text-white' : team.text}`}>{scores[idx]}</p>
                    </div>
                  </div>
                );
              })}
            </div>
            <div className="glass-panel p-6 rounded-[2rem] shadow-xl border-2 border-emerald-50">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Chủ đề hiện tại</label>
               <p className="text-lg font-black text-emerald-900 uppercase tracking-tight truncate">{theme?.name}</p>
            </div>
          </div>

          <div className="lg:col-span-9">
            <div className={`grid ${getGridCols()} gap-4 md:gap-6 p-8 glass-panel rounded-[3rem] shadow-2xl border-2 border-emerald-50`}>
              {cards.map((card, idx) => (
                <Card 
                  key={card.id} 
                  card={{...card, isFlipped: flippedIndices.includes(card.id) || lastMatchedPair.includes(card.id)}} 
                  index={idx}
                  onClick={handleCardClick}
                  disabled={status !== GameStatus.PLAYING}
                />
              ))}
            </div>
          </div>
        </main>
      )}

      {activeQuestion && <QuestionModal question={activeQuestion} onAnswer={handleAnswer} />}

      {status === GameStatus.WON && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[150] flex items-center justify-center p-6">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full text-center shadow-2xl relative overflow-hidden">
            <div className="relative z-10">
              <div className="text-8xl mb-8 animate-bounce">🏆</div>
              <h2 className="text-6xl font-black text-slate-900 mb-2">CHIẾN THẮNG!</h2>
              <p className="text-slate-500 font-bold uppercase tracking-widest mb-12">Bảng Xếp Hạng Cuối Cùng</p>

              <div className={`grid grid-cols-1 md:grid-cols-${Math.min(teams.length, 5)} gap-4 mb-12`}>
                 {scores.map((score, idx) => {
                   const isWinner = score === maxScore && score > 0;
                   const team = teams[idx];
                   return (
                     <div key={idx} className={`p-6 rounded-[2rem] transition-all transform ${isWinner ? `scale-110 ${team.light} border-4 ${team.border} shadow-2xl` : 'bg-slate-50 border-2 border-slate-100 opacity-60'}`}>
                       <p className="text-[10px] font-black text-slate-400 uppercase mb-2">{team.name}</p>
                       <p className={`text-4xl font-black ${team.text}`}>{score}</p>
                       {isWinner && <span className={`text-[10px] font-black ${team.text} uppercase mt-2 block animate-pulse`}>Quán Quân</span>}
                     </div>
                   );
                 })}
              </div>

              <button 
                onClick={() => setStatus(GameStatus.SETUP)}
                className="px-16 py-6 bg-emerald-600 text-white rounded-[2rem] font-black text-2xl shadow-xl hover:bg-emerald-700 active:scale-95 transition-all flex items-center gap-4 mx-auto"
              >
                <i className="fa-solid fa-play"></i> VÁN MỚI
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

